// Unit 34: Deutsche Welle
// Level: B2

const UNIT_34 =
{n:34,lang:"de",srcLang:"en",track:"v2",title:"Deutsche Welle",sub:"Von Küste zu Küste",icon:"🌊",level:"B2.2",color:"#7B5EE8",lessons:[
{id:"deu_r34l1",title:"Freie Fahrt",icon:"\ud83d\ude97",xp:15,board:true,steps:[
{type:"intro",title:"Freie Fahrt",desc:"Hit the Autobahn with the whole crew. Learn travel and geography vocabulary. Discover Germany beyond Berlin.",goals:["Learn 18 words about travel and geography","Experience the Autobahn with Lukas, Mia, Hildi, and Verumius","Discover Germany's diversity"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-a5-autobahn",trg:"Samstagmorgen. Ein gemietetes Auto steht vor Verumius' Haus. Lukas sitzt am Steuer, Sonnenbrille auf, Playlist bereit. Mia \u00f6ffnet eine Papierkarte, weil sie darauf besteht. Hildi klettert auf die R\u00fcckbank, schon misstrauisch. Verumius wirft seine Tasche in den Kofferraum und grinst.",src:"Saturday morning. A rented car is parked outside Verumius's building. Lukas is behind the wheel, sunglasses on, playlist ready. Mia opens a paper map because she insists. Hildi climbs into the back, already suspicious. Verumius throws his bag in the trunk and grins."},
{type:"story",speaker:"lukas",mood:"relaxed",art:"de-a5-autobahn",trg:"Also, Leute. Freiburg. Sechs Stunden. Autobahn. Keine Geschwindigkeitsbegrenzung. Seid ihr bereit?",src:"So, folks. Freiburg. Six hours. Autobahn. No speed limit. Are you ready?"},
{type:"story",speaker:"hildi",mood:"nervous",art:"de-a5-autobahn",trg:"Geschwindigkeitsbegrenzung gibt es schon, Lukas. Du f\u00e4hrst einfach zu schnell.",src:"There IS a speed limit, Lukas. You just drive too fast."},
{type:"story",speaker:"mia",mood:"amused",art:"de-a5-autobahn",trg:"Hildi, auf der A5 gibt es Abschnitte ohne Tempolimit. Lukas hat recht. Aber wir machen Zwischenstopps.",src:"Hildi, on the A5 there are sections without a speed limit. Lukas is right. But we will make stops along the way."},
{type:"story",speaker:"verumius",mood:"excited",art:"de-a5-autobahn",trg:"Ich war noch nie auf der Autobahn! Und noch nie in S\u00fcddeutschland. Bereisen wir das ganze Bundesland?",src:"I have never been on the Autobahn! And never in southern Germany. Are we going to travel through the whole state?"},
{type:"teach",trg:"das Bundesland",src:"federal state",pos:"noun",gender:"n",note:"Bund (federation) + Land (state/country). Germany has 16\nBundesl\u00e4nder, each with its own government and school system.",example:"A: In welchem Bundesland liegt Freiburg?\nB: In Baden-W\u00fcrttemberg.\nA: Wie viele Bundesl\u00e4nder hat Deutschland?\nB: Sechzehn, von Bayern bis Bremen.",exampleSrc:"A: In which federal state is Freiburg?\nB: In Baden-W\u00fcrttemberg.\nA: How many federal states does Germany have?\nB: Sixteen, from Bavaria to Bremen.",funFact:"Bund (federation) + Land (state/country). Germany has 16 Bundesl\u00e4nder, each with its own government, police, and school system. Berlin is both a city AND a Bundesland. Bavaria is the largest, Bremen the smallest."},
{type:"teach",trg:"die Region",src:"region",pos:"noun",gender:"f",note:"From Latin 'regio' (direction/district). Germany's regions\ndiffer wildly: coastal Friesland, alpine Bavaria, industrial Ruhr.",example:"A: Welche Region Deutschlands magst du am liebsten?\nB: Den S\u00fcdwesten. Die Landschaft ist wundersch\u00f6n.\nA: Jede Region hat ihren eigenen Dialekt.\nB: Und ihr eigenes Essen!",exampleSrc:"A: Which region of Germany do you like best?\nB: The southwest. The landscape is beautiful.\nA: Every region has its own dialect.\nB: And its own food!",funFact:"From Latin 'regio' (direction/district). Same word in English. Germany's regions differ wildly: coastal Friesland, alpine Bavaria, industrial Ruhrgebiet, wine-country Rhineland. Each has its own dialect and food."},
{type:"teach",trg:"die Durchfahrt",src:"transit, passage",pos:"noun",gender:"f",note:"Durch (through) + Fahrt (drive/trip). 'Keine Durchfahrt'\nis one of Germany's most common road signs.",example:"A: Ist hier Durchfahrt erlaubt?\nB: Nein, keine Durchfahrt.\nA: Dann m\u00fcssen wir umfahren.\nB: Ja, nimm die n\u00e4chste Ausfahrt.",exampleSrc:"A: Is transit allowed here?\nB: No, no through traffic.\nA: Then we have to go around.\nB: Yes, take the next exit.",funFact:"Durch (through) + Fahrt (drive/trip). A transit, a passage. 'Keine Durchfahrt' (No through traffic) is one of Germany's most common road signs. The word tells you: you drive THROUGH, not stop."},
{type:"teach",trg:"die Rastst\u00e4tte",src:"motorway service station",pos:"noun",gender:"f",note:"Rast (rest) + St\u00e4tte (place). German Rastst\u00e4tten are an\ninstitution: overpriced coffee, Currywurst, and paid toilets.",example:"A: Ich brauche eine Pause. Gibt es eine Rastst\u00e4tte?\nB: Ja, in zehn Kilometern.\nA: Haben Rastst\u00e4tten guten Kaffee?\nB: Nein, aber saubere Toiletten.",exampleSrc:"A: I need a break. Is there a service station?\nB: Yes, in ten kilometers.\nA: Do service stations have good coffee?\nB: No, but clean toilets.",funFact:"Rast (rest) + St\u00e4tte (place). German Rastst\u00e4tten are an institution: overpriced coffee, Currywurst, and clean toilets you pay to use. The famous Sanifair coin is a rite of passage."},
{type:"teach",trg:"der Wanderweg",src:"hiking trail",pos:"noun",gender:"m",note:"Wandern (to hike) + Weg (path). Germany has over 200,000 km\nof marked Wanderwege. Hiking is the national outdoor sport.",example:"A: Gibt es hier einen Wanderweg?\nB: Ja, der Wanderweg f\u00fchrt durch den Wald.\nA: Wie lang ist der Wanderweg?\nB: Etwa zwanzig Kilometer.",exampleSrc:"A: Is there a hiking trail here?\nB: Yes, the trail leads through the forest.\nA: How long is the hiking trail?\nB: About twenty kilometers.",funFact:"Wandern (to hike) + Weg (path). Germany has over 200,000 km of marked Wanderwege. Hiking is the national outdoor sport. Every region has its own long-distance Wanderweg."},
{type:"teach",trg:"der Zwischenstopp",src:"stopover, intermediate stop",pos:"noun",gender:"m",note:"Zwischen (between) + Stopp (stop). An intermediate stop.\n'Wir machen einen Zwischenstopp in Heidelberg.'",example:"A: Machen wir einen Zwischenstopp?\nB: Ja, in Heidelberg.\nA: Wie lange dauert der Zwischenstopp?\nB: Eine Stunde, dann fahren wir weiter.",exampleSrc:"A: Shall we make a stopover?\nB: Yes, in Heidelberg.\nA: How long will the stopover last?\nB: One hour, then we drive on.",funFact:"Zwischen (between) + Stopp (stop). An intermediate stop, a layover. 'Wir machen einen Zwischenstopp in Heidelberg.' The compound captures the between-ness perfectly."},
{type:"teach",trg:"bereisen",src:"to travel through, to tour",pos:"verb",gender:null,note:"Be- + reisen (to travel). The be- prefix makes it transitive:\nyou 'bereisen ein Land.' More thorough than just 'reisen.'",example:"A: Hast du ganz Deutschland bereist?\nB: Fast. Mir fehlt noch der Norden.\nA: Ich will S\u00fcddeutschland bereisen.\nB: Fang mit dem Schwarzwald an!",exampleSrc:"A: Have you traveled through all of Germany?\nB: Almost. I still need to see the north.\nA: I want to tour southern Germany.\nB: Start with the Black Forest!",funFact:"Be- + reisen (to travel). The be- prefix makes it transitive: you 'bereisen ein Land' (travel through a country). More thorough than just 'reisen.' Bereisen implies you explore the place properly."},
{type:"teach",trg:"durchqueren",src:"to traverse, to cross through",pos:"verb",gender:null,note:"Durch (through) + queren (to cross). Not separable.\n'Wir durchqueren drei Bundesl\u00e4nder.' One continuous crossing.",example:"A: Wie viele Bundesl\u00e4nder durchqueren wir?\nB: Drei: Hessen, Baden-W\u00fcrttemberg und Bayern.\nA: Durchqueren wir auch den Schwarzwald?\nB: Nein, den umfahren wir.",exampleSrc:"A: How many federal states are we crossing?\nB: Three: Hesse, Baden-W\u00fcrttemberg, and Bavaria.\nA: Are we crossing the Black Forest too?\nB: No, we are going around it.",funFact:"Durch (through) + queren (to cross). To traverse, to cross through. Not separable because durch- is inseparable here. 'Wir durchqueren drei Bundesl\u00e4nder.' One continuous crossing."},
{type:"teach",trg:"erkunden",src:"to explore, to scout out",pos:"verb",gender:null,note:"Er- + kunden (related to Kunde, knowledge). Military origin:\nErkundung was reconnaissance. Now means curious exploration.",example:"A: Wollen wir die Altstadt erkunden?\nB: Ja, zu Fu\u00df!\nA: Ich erkunde gern neue St\u00e4dte.\nB: Dann ist Freiburg perfekt f\u00fcr dich.",exampleSrc:"A: Shall we explore the old town?\nB: Yes, on foot!\nA: I like exploring new cities.\nB: Then Freiburg is perfect for you.",funFact:"Er- + kunden (related to Kunde, knowledge). To explore, to scout out. Military origin: Erkundung was reconnaissance. Now it means any kind of curious exploration. 'Die Stadt erkunden' (to explore the city)."},
{type:"teach",trg:"herumkommen",src:"to get around, to travel widely",pos:"verb",gender:null,note:"Herum (around) + kommen (to come). Separable. Colloquial.\n'Er ist viel herumgekommen' (He has traveled a lot).",example:"A: Bist du viel herumgekommen?\nB: Ja, ich war in zehn L\u00e4ndern.\nA: Man kommt hier gut herum.\nB: Stimmt, die Z\u00fcge fahren \u00fcberall hin.",exampleSrc:"A: Have you traveled around a lot?\nB: Yes, I have been to ten countries.\nA: You can get around well here.\nB: True, the trains go everywhere.",funFact:"Herum (around) + kommen (to come). To get around, to travel widely. Separable. 'Er ist viel herumgekommen' (He has traveled a lot). The image: you come around to many places."},
{type:"teach",trg:"wandern",src:"to hike",pos:"verb",gender:null,note:"Same root as English 'wander.' Germans take Wandern seriously:\nproper boots, trail maps, Wanderverein memberships.",example:"A: Gehen wir morgen wandern?\nB: Ja, im Schwarzwald.\nA: Wie lange wandern wir?\nB: F\u00fcnf Stunden, mit Pausen.",exampleSrc:"A: Shall we go hiking tomorrow?\nB: Yes, in the Black Forest.\nA: How long will we hike?\nB: Five hours, with breaks.",funFact:"Same root as English 'wander.' Germans take Wandern seriously: proper boots, trail maps, Wanderverein (hiking club) memberships. 'Wer wandert, der findet' is an old saying."},
{type:"teach",trg:"\u00fcbernachten",src:"to stay overnight",pos:"verb",gender:null,note:"\u00dcber (over) + Nacht (night). Literally 'to go over a night.'\nNot separable. 'Wo \u00fcbernachten wir?'",example:"A: Wo \u00fcbernachten wir in Freiburg?\nB: In einer Jugendherberge.\nA: Hast du schon mal im Zelt \u00fcbernachtet?\nB: Ja, auf einem Campingplatz im Schwarzwald.",exampleSrc:"A: Where are we staying overnight in Freiburg?\nB: In a youth hostel.\nA: Have you ever stayed overnight in a tent?\nB: Yes, at a campsite in the Black Forest.",funFact:"\u00dcber (over) + Nacht (night). To stay overnight. The word literally means to 'go over a night.' Not separable. 'Wo \u00fcbernachten wir?' is the first question on every road trip."},
{type:"teach",trg:"atemberaubend",src:"breathtaking",pos:"adj",gender:null,note:"Atem (breath) + beraubend (robbing). Literally breath-robbing.\nOne of German's most dramatic adjectives. Three components in one.",example:"A: Die Aussicht ist atemberaubend!\nB: Ja, man kann bis zu den Alpen sehen.\nA: Das Tal ist auch atemberaubend.\nB: Freiburg hat einfach alles.",exampleSrc:"A: The view is breathtaking!\nB: Yes, you can see all the way to the Alps.\nA: The valley is also breathtaking.\nB: Freiburg simply has everything.",funFact:"Atem (breath) + beraubend (robbing). Breathtaking, literally breath-robbing. 'Die Aussicht ist atemberaubend.' One of German's most dramatic adjectives. Three components welded into one word."},
{type:"teach",trg:"landschaftlich",src:"scenic, relating to landscape",pos:"adj",gender:null,note:"Landschaft (landscape) + -lich (suffix). 'Landschaftlich sch\u00f6n'\nis how Germans describe their favorite drives.",example:"A: Ist die Strecke landschaftlich sch\u00f6n?\nB: Ja, sehr. Berge, W\u00e4lder und Seen.\nA: Landschaftlich ist der S\u00fcden am besten.\nB: Da hast du recht.",exampleSrc:"A: Is the route scenic?\nB: Yes, very. Mountains, forests, and lakes.\nA: Scenically, the south is the best.\nB: You are right about that.",funFact:"Landschaft (landscape) + -lich (adjective suffix). Scenic, relating to landscape. 'Landschaftlich sch\u00f6n' (scenically beautiful) is how Germans describe their favorite drives."},
{type:"teach",trg:"malerisch",src:"picturesque",pos:"adj",gender:null,note:"From Maler (painter) + -isch. Literally 'painter-like.'\nA place so beautiful a painter would stop to capture it.",example:"A: Freiburg ist wirklich malerisch.\nB: Ja, besonders die Altstadt.\nA: Kennst du andere malerische St\u00e4dte?\nB: Heidelberg und Rothenburg sind auch malerisch.",exampleSrc:"A: Freiburg is truly picturesque.\nB: Yes, especially the old town.\nA: Do you know other picturesque cities?\nB: Heidelberg and Rothenburg are also picturesque.",funFact:"From Maler (painter) + -isch. Picturesque, literally 'painter-like.' A place so beautiful a painter would stop to capture it. 'Ein malerisches Dorf' (a picturesque village). The highest compliment for a landscape."},
{type:"teach",trg:"idyllisch",src:"idyllic",pos:"adj",gender:null,note:"From Greek 'eidyllion' (short pastoral poem). Same word\nacross European languages. Implies peace and rural charm.",example:"A: Das Dorf sieht idyllisch aus.\nB: Ja, total ruhig und friedlich.\nA: Ein idyllischer Ort zum \u00dcbernachten.\nB: Perfekt f\u00fcr eine Pause vom Alltag.",exampleSrc:"A: The village looks idyllic.\nB: Yes, totally quiet and peaceful.\nA: An idyllic place to stay overnight.\nB: Perfect for a break from everyday life.",funFact:"From Greek 'eidyllion' (short pastoral poem). Idyllic. Same word across European languages. 'Ein idyllischer Ort' (an idyllic place). Implies peace, rural charm, and absence of stress."},
{type:"teach",trg:"danach",src:"afterward, after that",pos:"adv",gender:null,note:"Da (there) + nach (after). A temporal adverb.\n'Zuerst Heidelberg, danach Freiburg.' Clean sequencing.",example:"A: Was machen wir zuerst?\nB: Zuerst die Altstadt, danach den Dom.\nA: Und danach?\nB: Danach essen wir etwas.",exampleSrc:"A: What do we do first?\nB: First the old town, then the cathedral.\nA: And after that?\nB: After that we eat something.",funFact:"Da (there) + nach (after). Afterward, after that. A temporal adverb. 'Zuerst Heidelberg, danach Freiburg.' Clean sequencing. Essential for storytelling and travel planning."},
{type:"teach",trg:"inzwischen",src:"meanwhile, in the meantime",pos:"adv",gender:null,note:"In + zwischen (between). Marks time passing between events.\n'Inzwischen hat sich viel ver\u00e4ndert.' Elegant and common.",example:"A: Wir fahren seit drei Stunden.\nB: Inzwischen hat es angefangen zu regnen.\nA: Inzwischen sind wir fast da.\nB: Gut, ich bin hungrig!",exampleSrc:"A: We have been driving for three hours.\nB: Meanwhile, it has started to rain.\nA: In the meantime, we are almost there.\nB: Good, I am hungry!",funFact:"In + zwischen (between). Meanwhile, in the meantime. 'Inzwischen hat sich viel ver\u00e4ndert' (Meanwhile, a lot has changed). Marks time passing between events. Elegant and commonly used."},
{type:"mc",q:"Wie viele Bundesl\u00e4nder hat Deutschland?",opts:["12","20","9","16"],ans:"16",hint:"The largest is Bavaria, the smallest is Bremen. The number is between 15 and 17."},
{type:"fb",s:"Wir wollen ganz S\u00fcddeutschland {1}.",a:["bereisen"],opts:["bereisen","reisen","fahren","gehen"],hint:"The verb with be- prefix meaning to travel thoroughly through a region.",sSrc:"We want to travel through all of southern Germany."}
]},
{id:"deu_r34l2",title:"Land und Leute",icon:"\ud83c\udff0",xp:15,board:true,steps:[
{type:"intro",title:"Land und Leute",desc:"Master vocabulary for German landmarks and cultural sites. Describe cities and their historical features. Plan sightseeing routes.",goals:["Learn 18 words about landmarks and culture","Describe cities and historical sites","Plan sightseeing tours"]},
{type:"teach",trg:"die Altstadt",src:"old town",pos:"noun",gender:"f",note:"Alt (old) + Stadt (city). Every German city with medieval roots\nhas an Altstadt: narrow streets, half-timbered houses.",example:"A: Hast du die Altstadt von Freiburg gesehen?\nB: Ja, sie ist wundersch\u00f6n.\nA: Die Altstadt hat enge Gassen.\nB: Und \u00fcberall flie\u00dft Wasser in den B\u00e4chle.",exampleSrc:"A: Have you seen the old town of Freiburg?\nB: Yes, it is beautiful.\nA: The old town has narrow lanes.\nB: And water flows everywhere in the little streams.",funFact:"Alt (old) + Stadt (city). Every German city with medieval roots has an Altstadt: narrow streets, half-timbered houses, a central Marktplatz. Freiburg's Altstadt survived WWII bombing mostly intact."},
{type:"teach",trg:"die Burg",src:"castle (fortified)",pos:"noun",gender:"f",note:"Same root as English 'borough' and French 'bourg.' A fortified\ncastle for military defense. Different from Schloss (palace).",example:"A: Ist das eine Burg oder ein Schloss?\nB: Eine Burg. Siehst du die dicken Mauern?\nA: Die Burg steht hoch auf dem Berg.\nB: Ja, zur Verteidigung.",exampleSrc:"A: Is that a castle or a palace?\nB: A castle. See the thick walls?\nA: The castle sits high on the hill.\nB: Yes, for defense.",funFact:"Same root as English 'borough' and French 'bourg.' A castle (fortified, military). Different from Schloss (palace, residential). Die Burg sits on hilltops for defense. Germany has over 25,000 Burgen and Schl\u00f6sser."},
{type:"teach",trg:"der Dom",src:"cathedral",pos:"noun",gender:"m",note:"From Latin 'domus Dei' (house of God). Der K\u00f6lner Dom took\n632 years to complete (1248-1880). Masculine from Latin origin.",example:"A: Der Freiburger Dom ist beeindruckend.\nB: Ja, der Turm ist 116 Meter hoch.\nA: Hast du den K\u00f6lner Dom gesehen?\nB: Ja, er ist noch gr\u00f6\u00dfer!",exampleSrc:"A: The Freiburg Cathedral is impressive.\nB: Yes, the tower is 116 meters high.\nA: Have you seen the Cologne Cathedral?\nB: Yes, it is even bigger!",funFact:"From Latin 'domus Dei' (house of God). A cathedral. Der K\u00f6lner Dom took 632 years to complete (1248-1880). Every major German city has its Dom. Masculine because of the Latin origin."},
{type:"teach",trg:"das Schloss",src:"palace, stately home",pos:"noun",gender:"n",note:"From schlie\u00dfen (to close/lock). Originally a 'locked' building.\nSchloss Neuschwanstein inspired Disney's castle. Neuter.",example:"A: Schloss Neuschwanstein ist weltber\u00fchmt.\nB: Ja, der Disneypalast!\nA: Gibt es ein Schloss in Freiburg?\nB: Nicht direkt, aber mehrere in der Region.",exampleSrc:"A: Neuschwanstein Palace is world-famous.\nB: Yes, the Disney palace!\nA: Is there a palace in Freiburg?\nB: Not directly, but several in the region.",funFact:"From schlie\u00dfen (to close/lock). Originally a 'locked' building. Schloss Neuschwanstein inspired Disney's castle. Das Schloss is neuter. Distinction: Burg = fortress, Schloss = residence."},
{type:"teach",trg:"der Marktplatz",src:"market square",pos:"noun",gender:"m",note:"Markt (market) + Platz (square). The Rathaus usually faces\nthe Marktplatz. Christmas markets set up here every December.",example:"A: Treffen wir uns auf dem Marktplatz?\nB: Ja, vor dem Rathaus.\nA: Der Marktplatz ist voller Menschen.\nB: Heute ist Markttag!",exampleSrc:"A: Shall we meet at the market square?\nB: Yes, in front of the town hall.\nA: The market square is full of people.\nB: Today is market day!",funFact:"Markt (market) + Platz (square). The central market square. Every traditional German town has one. The Rathaus (town hall) usually faces the Marktplatz. Christmas markets set up here every December."},
{type:"teach",trg:"die Stadtmauer",src:"city wall",pos:"noun",gender:"f",note:"Stadt (city) + Mauer (wall). Many German cities still have\nmedieval Stadtmauern: Rothenburg, N\u00fcrnberg, L\u00fcbeck.",example:"A: Kann man auf der Stadtmauer spazieren?\nB: Ja, in Rothenburg geht das.\nA: Die Stadtmauer ist \u00fcber 500 Jahre alt.\nB: Und immer noch stabil!",exampleSrc:"A: Can you walk along the city wall?\nB: Yes, in Rothenburg you can.\nA: The city wall is over 500 years old.\nB: And still sturdy!",funFact:"Stadt (city) + Mauer (wall). A city wall. Many German cities still have sections of their medieval Stadtmauer: Rothenburg, N\u00fcrnberg, L\u00fcbeck. Walking along the Stadtmauer is a top tourist activity."},
{type:"teach",trg:"das Wahrzeichen",src:"landmark, emblem",pos:"noun",gender:"n",note:"Wahr (true) + Zeichen (sign). Das Brandenburger Tor ist\nBerlins Wahrzeichen. Every city has one defining symbol.",example:"A: Was ist das Wahrzeichen von Freiburg?\nB: Das Freiburger M\u00fcnster.\nA: Und Berlins Wahrzeichen?\nB: Das Brandenburger Tor, nat\u00fcrlich.",exampleSrc:"A: What is Freiburg's landmark?\nB: The Freiburg Minster.\nA: And Berlin's landmark?\nB: The Brandenburg Gate, of course.",funFact:"Wahr (true) + Zeichen (sign). A landmark, an emblem. The Brandenburger Tor is Berlin's Wahrzeichen. Every city has one thing that defines it visually. Das Wahrzeichen is neuter."},
{type:"teach",trg:"die Sehensw\u00fcrdigkeit",src:"tourist attraction, sight",pos:"noun",gender:"f",note:"Sehen (see) + w\u00fcrdig (worthy) + -keit (suffix). One of German's\nlongest everyday compounds. Worth seeing.",example:"A: Was sind die Top-Sehensw\u00fcrdigkeiten in Freiburg?\nB: Der Dom, die B\u00e4chle und der Schlossberg.\nA: Gibt es viele Sehensw\u00fcrdigkeiten?\nB: Ja, man braucht mindestens zwei Tage.",exampleSrc:"A: What are the top sights in Freiburg?\nB: The cathedral, the little streams, and the castle hill.\nA: Are there many sights?\nB: Yes, you need at least two days.",funFact:"Sehen (see) + w\u00fcrdig (worthy) + -keit (noun suffix). A sight worth seeing, a tourist attraction. One of German's longest everyday compounds. 'Die Top-10-Sehensw\u00fcrdigkeiten' appears on every travel website."},
{type:"teach",trg:"der Weinberg",src:"vineyard",pos:"noun",gender:"m",note:"Wein (wine) + Berg (mountain/hill). Germany has 13 wine regions.\nMasculine because Berg is masculine.",example:"A: Siehst du die Weinberge?\nB: Ja, sie sind \u00fcberall an den H\u00fcgeln.\nA: Freiburg liegt mitten in Weinbergen.\nB: Deshalb ist der Wein hier so gut.",exampleSrc:"A: Do you see the vineyards?\nB: Yes, they are all over the hills.\nA: Freiburg lies in the middle of vineyards.\nB: That is why the wine here is so good.",funFact:"Wein (wine) + Berg (mountain/hill). A vineyard. Germany has 13 wine regions. The steep Weinberge along the Mosel and Rhine produce world-class Riesling. Masculine because Berg is masculine."},
{type:"teach",trg:"das Freibad",src:"outdoor swimming pool",pos:"noun",gender:"n",note:"Frei (open/free) + Bad (bath/pool). Germans love their Freib\u00e4der\nin summer. The season runs May to September. Neuter.",example:"A: Gehen wir ins Freibad?\nB: Ja, bei dem Wetter perfekt!\nA: Freiburg hat ein sch\u00f6nes Freibad.\nB: Mit Blick auf die Berge!",exampleSrc:"A: Shall we go to the outdoor pool?\nB: Yes, perfect in this weather!\nA: Freiburg has a nice outdoor pool.\nB: With a view of the mountains!",funFact:"Frei (open/free) + Bad (bath/pool). An outdoor swimming pool. Germans love their Freib\u00e4der in summer. Every town has one. The Freibad season runs May to September. Neuter because Bad is neuter."},
{type:"teach",trg:"die Stadtf\u00fchrung",src:"city tour",pos:"noun",gender:"f",note:"Stadt (city) + F\u00fchrung (guided tour). Feminine because F\u00fchrung\nis feminine. Free walking tours are popular in every German city.",example:"A: Sollen wir eine Stadtf\u00fchrung machen?\nB: Ja, gute Idee!\nA: Die Stadtf\u00fchrung dauert zwei Stunden.\nB: Perfekt, dann sehen wir alles.",exampleSrc:"A: Shall we take a city tour?\nB: Yes, good idea!\nA: The city tour lasts two hours.\nB: Perfect, then we will see everything.",funFact:"Stadt (city) + F\u00fchrung (guided tour). A city tour. 'Eine Stadtf\u00fchrung machen' (to take a city tour). Feminine because F\u00fchrung is feminine. Free walking tours are popular in every German city."},
{type:"teach",trg:"historisch",src:"historical",pos:"adj",gender:null,note:"From Greek 'historia.' Same word across European languages.\nGermans are meticulous about preserving historische Bausubstanz.",example:"A: Ist das ein historisches Geb\u00e4ude?\nB: Ja, aus dem 14. Jahrhundert.\nA: Die historische Altstadt ist gesch\u00fctzt.\nB: Ja, man darf nichts ver\u00e4ndern.",exampleSrc:"A: Is that a historical building?\nB: Yes, from the 14th century.\nA: The historical old town is protected.\nB: Yes, you are not allowed to change anything.",funFact:"From Greek 'historia.' Historical. Same word across European languages. 'Ein historisches Geb\u00e4ude' (a historical building). Germans are meticulous about preserving historische Bausubstanz (historical building fabric)."},
{type:"teach",trg:"mittelalterlich",src:"medieval",pos:"adj",gender:null,note:"Mittelalter (Middle Ages) + -lich. The Mittelalter lasted roughly\nfrom 500-1500 AD. Many Altst\u00e4dte still look mittelalterlich.",example:"A: Diese Burg ist mittelalterlich.\nB: Ja, aus dem 12. Jahrhundert.\nA: Die mittelalterlichen Gassen sind eng.\nB: Aber wundersch\u00f6n.",exampleSrc:"A: This castle is medieval.\nB: Yes, from the 12th century.\nA: The medieval lanes are narrow.\nB: But beautiful.",funFact:"Mittelalter (Middle Ages) + -lich. Medieval. 'Eine mittelalterliche Burg' (a medieval castle). The Mittelalter lasted roughly from 500-1500 AD. Many German cities still look mittelalterlich in their Altstadt."},
{type:"teach",trg:"sehenswert",src:"worth seeing",pos:"adj",gender:null,note:"Sehen (to see) + wert (worth). Shorter than Sehensw\u00fcrdigkeit\nbut same root. A practical adjective for travel tips.",example:"A: Ist Freiburg sehenswert?\nB: Auf jeden Fall!\nA: Was ist besonders sehenswert?\nB: Der Dom und die B\u00e4chle.",exampleSrc:"A: Is Freiburg worth seeing?\nB: Absolutely!\nA: What is especially worth seeing?\nB: The cathedral and the little streams.",funFact:"Sehen (to see) + wert (worth). Worth seeing. Shorter than Sehensw\u00fcrdigkeit but same root. 'Die Altstadt ist sehenswert' (The old town is worth seeing). A practical adjective for travel recommendations."},
{type:"teach",trg:"reizvoll",src:"charming, attractive",pos:"adj",gender:null,note:"Reiz (charm/stimulus) + voll (full). More subtle than 'sch\u00f6n.'\nImplies something that draws you in gently.",example:"A: Die Landschaft hier ist reizvoll.\nB: Ja, die H\u00fcgel und Weinberge.\nA: Ein reizvolles Dorf!\nB: Perfekt f\u00fcr einen Zwischenstopp.",exampleSrc:"A: The landscape here is charming.\nB: Yes, the hills and vineyards.\nA: A charming village!\nB: Perfect for a stopover.",funFact:"Reiz (charm/stimulus) + voll (full). Charming, attractive, full of appeal. 'Eine reizvolle Landschaft' (a charming landscape). More subtle than 'sch\u00f6n.' Implies something that draws you in gently."},
{type:"teach",trg:"pittoresk",src:"picturesque (formal)",pos:"adj",gender:null,note:"From French 'pittoresque,' from Italian 'pittoresco.'\nSame meaning as 'malerisch' but more formal and literary.",example:"A: Das Dorf ist wirklich pittoresk.\nB: Ja, wie aus einem Gem\u00e4lde.\nA: 'Pittoresk' klingt sehr elegant.\nB: Es kommt aus dem Franz\u00f6sischen.",exampleSrc:"A: The village is truly picturesque.\nB: Yes, like out of a painting.\nA: 'Pittoresk' sounds very elegant.\nB: It comes from French.",funFact:"From French 'pittoresque,' from Italian 'pittoresco' (painter-like). Picturesque. Same meaning as 'malerisch' but with a French flavor. Used in formal writing and travel literature. An elegant synonym."},
{type:"teach",trg:"eindrucksvoll",src:"impressive",pos:"adj",gender:null,note:"Eindruck (impression) + voll (full). Full of impression.\n'Ein eindrucksvolles Bauwerk.' The opposite of 'unscheinbar.'",example:"A: Der Dom ist wirklich eindrucksvoll.\nB: Ja, besonders von innen.\nA: Ein eindrucksvolles Bauwerk.\nB: Man f\u00fchlt sich ganz klein davor.",exampleSrc:"A: The cathedral is truly impressive.\nB: Yes, especially from the inside.\nA: An impressive structure.\nB: You feel very small in front of it.",funFact:"Eindruck (impression) + voll (full). Impressive, full of impression. 'Ein eindrucksvolles Bauwerk' (an impressive structure). The opposite of 'unscheinbar' (inconspicuous)."},
{type:"teach",trg:"besichtigen",src:"to visit, to tour (a place)",pos:"verb",gender:null,note:"Be- + sichtigen (from Sicht, sight). The be- prefix makes it\ntransitive. Implies a thorough, deliberate look.",example:"A: Wollen wir das Schloss besichtigen?\nB: Ja, die F\u00fchrung beginnt um zehn.\nA: Kann man den Dom auch besichtigen?\nB: Ja, der Eintritt ist frei.",exampleSrc:"A: Shall we visit the palace?\nB: Yes, the tour starts at ten.\nA: Can you visit the cathedral too?\nB: Yes, admission is free.",funFact:"Be- + sichtigen (from Sicht, sight). To visit, to tour, to inspect. 'Das Schloss besichtigen' (to visit the castle). The be- prefix makes it transitive: you besichtigen a place. Implies a thorough look."},
{type:"mc",q:"Was ist der Unterschied zwischen einer Burg und einem Schloss?",opts:["Burg ist eine Festung, Schloss ist ein Wohnpalast","Burg ist gr\u00f6\u00dfer als ein Schloss","Burg ist neuer als ein Schloss","Beide bedeuten dasselbe"],ans:"Burg ist eine Festung, Schloss ist ein Wohnpalast",hint:"One stands on hilltops for defense. The other was the residence of the nobility."},
{type:"match",pairs:[{trg:"Altstadt",src:"old town"},{trg:"Wahrzeichen",src:"landmark"},{trg:"Dom",src:"cathedral"},{trg:"Marktplatz",src:"market square"},{trg:"Weinberg",src:"vineyard"}]},
{type:"fb",s:"Morgen wollen wir das Schloss {1}.",a:["besichtigen"],opts:["besichtigen","besuchen","sehen","schauen"],hint:"The formal verb with be- prefix for a thorough visit to a place.",sSrc:"Tomorrow we want to visit the palace."},
{type:"mc",q:"Ein kleines Dorf mit Fachwerkh\u00e4usern an einem Fluss. Welches Adjektiv passt am besten?",opts:["eindrucksvoll","malerisch","historisch","atemberaubend"],ans:"malerisch",hint:"A place so beautiful that a painter would want to capture it.",sSrc:"A small village with half-timbered houses by a river. Which adjective fits best?"},
{type:"drag_fill",s:"Freiburg hat eine {1} Altstadt mit einem {2} Dom und vielen {3}.",blanks:{"1":"mittelalterliche","2":"eindrucksvollen","3":"Sehensw\u00fcrdigkeiten"},pool:["mittelalterliche","eindrucksvollen","Sehensw\u00fcrdigkeiten","historischen","malerische","Wanderwege"],hint:"A medieval old town, an impressive cathedral, and many places worth seeing.",sSrc:"Freiburg has a medieval old town with an impressive cathedral and many sights."}
]},
{id:"deu_r34l3",title:"Un-, miss-, zer-",icon:"\ud83d\udd87\ufe0f",xp:15,board:true,steps:[
{type:"intro",title:"Un-, miss-, zer-",desc:"Learn the three negation prefixes that darken German words. Understand regional dialects and linguistic diversity. Play with word formation.",goals:["Learn the prefixes un-, miss-, and zer-","Understand regional dialects and language variation","Play with word formation and chain words"]},
{type:"story",speaker:"narrator",mood:"calm",art:"de-a5-stau",trg:"Die A5. Was als Freiheit auf offener Stra\u00dfe begann, ist jetzt eine Wand aus roten Bremslichtern. Stau. Das ewige Autobahn-Erlebnis.",src:"The A5. What started as open-road freedom is now a solid wall of red brake lights. Traffic jam. The eternal Autobahn experience."},
{type:"story",speaker:"lukas",mood:"frustrated",art:"de-a5-stau",trg:"Stau. Nat\u00fcrlich. Immer vor Karlsruhe. Sollen wir ein Spiel spielen?",src:"Traffic jam. Of course. Always before Karlsruhe. Shall we play a game?"},
{type:"story",speaker:"mia",mood:"cheerful",art:"de-a5-stau",trg:"Kettenwort! Jeder sagt ein Wort, das mit dem letzten Teil anf\u00e4ngt. Ich fange an: Kuchen.",src:"Chain word! Everyone says a word that starts with the last part. I will start: Kuchen (cake)."},
{type:"story",speaker:"hildi",mood:"competitive",art:"de-a5-stau",trg:"Kuchentisch.",src:"Kuchentisch (cake table)."},
{type:"story",speaker:"lukas",mood:"thinking",art:"de-a5-stau",trg:"Tischdecke.",src:"Tischdecke (tablecloth)."},
{type:"story",speaker:"hildi",mood:"quick",art:"de-a5-stau",trg:"Deckenlampe.",src:"Deckenlampe (ceiling lamp)."},
{type:"story",speaker:"verumius",mood:"proud",art:"de-a5-stau",trg:"Lampenfieber!",src:"Lampenfieber (stage fright)!"},
{type:"story",speaker:"mia",mood:"impressed",art:"de-a5-stau",trg:"Lampenfieber! Das ist ein sch\u00f6nes Wort! Verumius gewinnt diese Runde.",src:"Lampenfieber! That is a beautiful word! Verumius wins this round."},
{type:"teach",trg:"missverstehen",src:"to misunderstand",pos:"verb",gender:null,note:"Miss- (wrongly) + verstehen (to understand). Not separable.\n'Da hast du mich missverstanden.' Related to English 'mis-.'",example:"A: Du hast mich missverstanden.\nB: Entschuldigung! Was meinst du?\nA: Missverst\u00e4ndnisse passieren oft.\nB: Besonders in einer Fremdsprache.",exampleSrc:"A: You misunderstood me.\nB: Sorry! What do you mean?\nA: Misunderstandings happen often.\nB: Especially in a foreign language.",funFact:"Miss- (wrongly) + verstehen (to understand). To misunderstand. 'Da hast du mich missverstanden.' The miss- prefix means something went wrong. Not separable. Related to English 'mis-' (misunderstand, mislead)."},
{type:"teach",trg:"zerst\u00f6ren",src:"to destroy",pos:"verb",gender:null,note:"Zer- (apart, to pieces) + st\u00f6ren (to disturb). The most violent\nprefix. Zerbrechen, zerrei\u00dfen, zerfallen. Destruction is always zer-.",example:"A: Der Sturm hat das Dach zerst\u00f6rt.\nB: Wie schrecklich.\nA: Kann man es reparieren?\nB: Ja, aber es dauert Wochen.",exampleSrc:"A: The storm destroyed the roof.\nB: How terrible.\nA: Can it be repaired?\nB: Yes, but it takes weeks.",funFact:"Zer- (apart, to pieces) + st\u00f6ren (to disturb). To destroy. The zer- prefix is the most violent: it means to break into pieces. Zerbrechen (break apart), zerrei\u00dfen (tear apart), zerfallen (fall apart)."},
{type:"teach",trg:"die Mundart",src:"dialect (literary term)",pos:"noun",gender:"f",note:"Mund (mouth) + Art (way/type). Literally 'the way of the mouth.'\nMore literary than Dialekt. Feminine.",example:"A: Sprichst du eine Mundart?\nB: Ja, Schw\u00e4bisch.\nA: Die bayerische Mundart klingt ganz anders.\nB: Ja, wie eine eigene Sprache.",exampleSrc:"A: Do you speak a dialect?\nB: Yes, Swabian.\nA: The Bavarian dialect sounds completely different.\nB: Yes, like its own language.",funFact:"Mund (mouth) + Art (way/type). Dialect, literally 'the way of the mouth.' A more literary/academic term than Dialekt. 'Die bayerische Mundart' (the Bavarian dialect). Every region has its own Mundart."},
{type:"teach",trg:"das Hochdeutsch",src:"Standard German",pos:"noun",gender:"n",note:"Hoch (high) + Deutsch. Originally the language of the southern\nhighlands. Now the prestige dialect taught in schools and on TV.",example:"A: Sprichst du Hochdeutsch?\nB: Ja, aber mit leichtem Akzent.\nA: Im Fernsehen h\u00f6rt man nur Hochdeutsch.\nB: Ja, Dialekt ist selten im TV.",exampleSrc:"A: Do you speak Standard German?\nB: Yes, but with a slight accent.\nA: On TV you only hear Standard German.\nB: Yes, dialect is rare on TV.",funFact:"Hoch (high) + Deutsch. Originally referred to the language of the southern highlands (where German consonant shifts happened). Now means the prestige dialect taught in schools and used on TV."},
{type:"teach",trg:"die Umgangssprache",src:"colloquial language",pos:"noun",gender:"f",note:"Umgang (interaction) + Sprache (language). Between Hochdeutsch\nand Dialekt. The relaxed German people actually speak.",example:"A: 'Cool' ist Umgangssprache.\nB: Ja, nicht Hochdeutsch.\nA: Umgangssprache lernt man nicht im Buch.\nB: Nein, nur im echten Leben.",exampleSrc:"A: 'Cool' is colloquial language.\nB: Yes, not Standard German.\nA: You do not learn colloquial language from a book.\nB: No, only in real life.",funFact:"Umgang (interaction) + Sprache (language). Colloquial language, everyday speech. Between Hochdeutsch and Dialekt sits Umgangssprache: the relaxed German people actually speak. Regional color without full dialect."},
{type:"teach",trg:"der Muttersprachler",src:"native speaker",pos:"noun",gender:"m",note:"Muttersprache (mother tongue) + -ler (person). The -ler suffix\nturns a concept into the person who embodies it.",example:"A: Bist du Muttersprachler?\nB: Ja, Deutsch ist meine Muttersprache.\nA: Verumius will klingen wie ein Muttersprachler.\nB: Er wird es schaffen!",exampleSrc:"A: Are you a native speaker?\nB: Yes, German is my mother tongue.\nA: Verumius wants to sound like a native speaker.\nB: He will make it!",funFact:"Muttersprache (mother tongue) + -ler (person). A native speaker. 'Er spricht wie ein Muttersprachler.' The -ler suffix turns a concept into the person who embodies it."},
{type:"teach",trg:"der Dialekt",src:"dialect",pos:"noun",gender:"m",note:"From Greek 'dialektos' (manner of speaking). Germany has dozens:\nBayerisch, Schw\u00e4bisch, S\u00e4chsisch, K\u00f6lsch, Plattdeutsch.",example:"A: Welchen Dialekt spricht man hier?\nB: Schw\u00e4bisch.\nA: Manche Dialekte brauchen Untertitel im Fernsehen.\nB: Ja, besonders S\u00e4chsisch!",exampleSrc:"A: Which dialect do they speak here?\nB: Swabian.\nA: Some dialects need subtitles on TV.\nB: Yes, especially Saxon!",funFact:"From Greek 'dialektos' (manner of speaking). A regional variety of a language. Germany has dozens: Bayerisch, Schw\u00e4bisch, S\u00e4chsisch, K\u00f6lsch, Plattdeutsch. Some are so different they need subtitles on TV."},
{type:"teach",trg:"das Plattdeutsch",src:"Low German",pos:"noun",gender:"n",note:"Platt (flat/low) + Deutsch. Spoken in northern Germany's flat\nlowlands. Closer to Dutch and English than to Hochdeutsch.",example:"A: Sprichst du Plattdeutsch?\nB: Nur ein bisschen. Moin!\nA: 'Moin' ist Plattdeutsch?\nB: Ja, das ber\u00fchmteste Wort.",exampleSrc:"A: Do you speak Low German?\nB: Just a little bit. Moin!\nA: 'Moin' is Low German?\nB: Yes, the most famous word.",funFact:"Platt (flat/low) + Deutsch. Low German. Spoken in northern Germany's flat lowlands. A separate language branch, closer to Dutch and English than to Hochdeutsch. 'Moin!' (Hello!) is the most famous Plattdeutsch word."},
{type:"teach",trg:"das Schw\u00e4bisch",src:"Swabian (dialect)",pos:"noun",gender:"n",note:"The dialect of Swabia (Baden-W\u00fcrttemberg). Famous for 'schaffen'\n(to work hard) and 'Kehrwoche' (weekly cleaning rotation).",example:"A: Verstehst du Schw\u00e4bisch?\nB: Kaum! Es klingt so anders.\nA: Schw\u00e4bisch hat eigene Grammatik.\nB: Ja, fast eine eigene Sprache.",exampleSrc:"A: Do you understand Swabian?\nB: Hardly! It sounds so different.\nA: Swabian has its own grammar.\nB: Yes, almost its own language.",funFact:"The dialect of Swabia (Baden-W\u00fcrttemberg). Famous for 'schaffen' (to work hard) and 'Kehrwoche' (weekly cleaning rotation). Swabian speakers are stereotyped as thrifty, hardworking, and proud of their dialect."},
{type:"teach",trg:"norddeutsch",src:"northern German",pos:"adj",gender:null,note:"Nord (north) + deutsch. Norddeutsch culture is flatter, dryer\n(in humor and landscape), and more reserved.",example:"A: Norddeutsches Essen ist anders als s\u00fcddeutsches.\nB: Ja, mehr Fisch und weniger Kn\u00f6del.\nA: Norddeutsche sind reservierter.\nB: Aber sehr freundlich, wenn man sie kennt.",exampleSrc:"A: Northern German food is different from southern.\nB: Yes, more fish and fewer dumplings.\nA: Northern Germans are more reserved.\nB: But very friendly once you know them.",funFact:"Nord (north) + deutsch. Northern German. Norddeutsch culture is flatter, dryer (in humor and landscape), and more reserved. 'Moin' (morning greeting at any time of day) is quintessentially norddeutsch."},
{type:"teach",trg:"s\u00fcddeutsch",src:"southern German",pos:"adj",gender:null,note:"S\u00fcd (south) + deutsch. S\u00fcddeutsche Regionen haben st\u00e4rkere\nDialekte, katholische Traditionen und anderes Essen.",example:"A: S\u00fcddeutschland ist ganz anders als der Norden.\nB: Ja, andere Dialekte, anderes Essen.\nA: S\u00fcddeutsche Sp\u00e4tzle sind fantastisch.\nB: Und Brezeln erst!",exampleSrc:"A: Southern Germany is completely different from the north.\nB: Yes, different dialects, different food.\nA: Southern German Sp\u00e4tzle are fantastic.\nB: And pretzels even more so!",funFact:"S\u00fcd (south) + deutsch. Southern German. S\u00fcddeutsch regions (Bayern, Baden-W\u00fcrttemberg) have stronger dialects, Catholic traditions, and different food (Sp\u00e4tzle, Wei\u00dfwurst, Brezeln)."},
{type:"teach",trg:"bayrisch",src:"Bavarian",pos:"adj",gender:null,note:"From Bayern (Bavaria). The most famous German dialect\ninternationally, thanks to Oktoberfest.",example:"A: Sprichst du Bayrisch?\nB: A bissl! Servus!\nA: 'Servus' ist Bayrisch f\u00fcr Hallo?\nB: Ja, und auch f\u00fcr Tsch\u00fcss.",exampleSrc:"A: Do you speak Bavarian?\nB: A little! Servus!\nA: 'Servus' is Bavarian for hello?\nB: Yes, and also for goodbye.",funFact:"From Bayern (Bavaria). The most famous German dialect internationally, thanks to Oktoberfest. 'Servus' (hello/goodbye), 'Gr\u00fc\u00df Gott' (greeting), 'Oans, zwoa, drei' (one, two, three)."},
{type:"teach",trg:"urspr\u00fcnglich",src:"original, originally",pos:"adj",gender:null,note:"Ursprung (origin) + -lich. Three syllables packed with meaning.\n'Urspr\u00fcnglich wollte ich nach M\u00fcnchen.'",example:"A: Woher kommt das Wort urspr\u00fcnglich?\nB: Aus dem Mittelhochdeutschen.\nA: Urspr\u00fcnglich wollten wir nach M\u00fcnchen.\nB: Aber Freiburg ist besser!",exampleSrc:"A: Where does the word originally come from?\nB: From Middle High German.\nA: Originally we wanted to go to Munich.\nB: But Freiburg is better!",funFact:"Ursprung (origin) + -lich. Original, originally, in its original form. 'Urspr\u00fcnglich wollte ich nach M\u00fcnchen' (Originally I wanted to go to Munich). Three syllables packed with meaning."},
{type:"teach",trg:"altert\u00fcmlich",src:"old-fashioned, archaic",pos:"adj",gender:null,note:"Altertum (antiquity) + -lich. Describes language or customs\nthat feel like they come from another century.",example:"A: Dieses Wort klingt altert\u00fcmlich.\nB: Ja, niemand benutzt es mehr.\nA: Der Dialekt klingt manchmal altert\u00fcmlich.\nB: Ja, er hat alte Formen bewahrt.",exampleSrc:"A: This word sounds archaic.\nB: Yes, nobody uses it anymore.\nA: The dialect sometimes sounds archaic.\nB: Yes, it has preserved old forms.",funFact:"Altertum (antiquity) + -lich. Old-fashioned, archaic. Describes language or customs that feel like they come from another century. Not 'alt' (old), but 'from ancient times.'"},
{type:"teach",trg:"gleichzeitig",src:"simultaneous, at the same time",pos:"adv",gender:null,note:"Gleich (same) + zeitig (related to time). A temporal adverb.\nElegant way to describe parallel events.",example:"A: Kann man gleichzeitig fahren und essen?\nB: Lieber nicht!\nA: Gleichzeitig regnet es und scheint die Sonne.\nB: Typisch f\u00fcr den Schwarzwald!",exampleSrc:"A: Can you drive and eat at the same time?\nB: Better not!\nA: It is raining and the sun is shining at the same time.\nB: Typical for the Black Forest!",funFact:"Gleich (same) + zeitig (related to time). Simultaneous, at the same time. 'Gleichzeitig regnet es und scheint die Sonne.' Elegant way to describe parallel events."},
{type:"teach",trg:"unterdessen",src:"meanwhile (literary)",pos:"adv",gender:null,note:"Unter (under/during) + dessen (of that). More literary than\n'inzwischen.' Sets scenes beautifully in narrative.",example:"A: Lukas fuhr weiter.\nB: Unterdessen schlief Hildi ein.\nA: Unterdessen wurde es dunkel.\nB: Und der Stau l\u00f6ste sich auf.",exampleSrc:"A: Lukas drove on.\nB: Meanwhile, Hildi fell asleep.\nA: Meanwhile, it got dark.\nB: And the traffic jam cleared.",funFact:"Unter (under/during) + dessen (of that). Meanwhile, in the meantime. More literary than 'inzwischen.' 'Unterdessen spielten sie ein Wortspiel.' Sets scenes beautifully in narrative."},
{type:"teach",trg:"deswegen",src:"because of this, therefore",pos:"adv",gender:null,note:"Des (of this) + wegen (because of). A kausal adverb.\n'Es regnete, deswegen blieben wir im Auto.' Same as 'deshalb.'",example:"A: Es regnet. Deswegen bleiben wir im Auto.\nB: Gute Idee.\nA: Der Stau ist lang. Deswegen spielen wir.\nB: Deswegen liebe ich Wortspiele!",exampleSrc:"A: It is raining. That is why we are staying in the car.\nB: Good idea.\nA: The traffic jam is long. That is why we are playing.\nB: That is why I love word games!",funFact:"Des (of this) + wegen (because of). Because of this, therefore. A causal adverb. 'Es regnete, deswegen blieben wir im Auto.' Cause and effect in one word. Same meaning as 'deshalb.'"},
{type:"teach",trg:"deshalb",src:"therefore, for that reason",pos:"adv",gender:null,note:"Des (of this) + halb (half/behalf). Interchangeable with\n'deswegen.' The causal bridge between two facts.",example:"A: Ich liebe Sprachen, deshalb lerne ich Deutsch.\nB: Das ist ein guter Grund!\nA: Freiburg ist sch\u00f6n, deshalb fahren wir hin.\nB: Deshalb freue ich mich so!",exampleSrc:"A: I love languages, that is why I am learning German.\nB: That is a good reason!\nA: Freiburg is beautiful, that is why we are going there.\nB: That is why I am so excited!",funFact:"Des (of this) + halb (half/behalf). Therefore, for that reason. Interchangeable with 'deswegen.' 'Ich liebe Sprachen, deshalb lerne ich Deutsch.' The causal bridge between two facts."},
{type:"tip",title:"Negationspr\u00e4fixe: un-, miss-, zer-",text:"Three prefixes that darken, reverse, or destroy words.\n\nun- = opposite (mild)\ngl\u00fccklich \u2192 ungl\u00fccklich (unhappy)\nm\u00f6glich \u2192 unm\u00f6glich (impossible)\nfreundlich \u2192 unfreundlich (unfriendly)\n\nmiss- = done wrongly (error)\nverstehen \u2192 missverstehen (to misunderstand)\nErfolg \u2192 Misserfolg (failure)\ntrauen \u2192 misstrauen (to distrust)\n\nzer- = into pieces (destruction)\nst\u00f6ren \u2192 zerst\u00f6ren (to destroy)\nbrechen \u2192 zerbrechen (to shatter)\nrei\u00dfen \u2192 zerrei\u00dfen (to tear apart)\n\nPattern: un- is mild, miss- is an error, zer- is violent destruction. All three are inseparable prefixes.",deepDive:{title:"Negation prefixes in depth",text:"Un- is the mildest negation prefix. It creates opposites, just like English 'un-': happy/unhappy, friendly/unfriendly. Some un- words have shifted meaning: 'Ungeheuer' originally meant 'un-homely' but now means 'monster.'\n\nMiss- indicates something done wrongly or a failure. The prefix is always unstressed. 'Missverst\u00e4ndnis' (misunderstanding), 'Misserfolg' (failure), 'Missbrauch' (misuse/abuse). English 'mis-' works the same way.\n\nZer- is the most destructive. It means 'to pieces' or 'apart.' Every zer- verb implies violent fragmentation: zerbrechen (break to pieces), zerrei\u00dfen (tear apart), zerfallen (fall apart), zerschlagen (smash to pieces). Zer- is always inseparable."}},
{type:"mc",q:"Welches Pr\u00e4fix bedeutet 'in St\u00fccke' oder 'auseinander'?",opts:["un-","miss-","zer-","ver-"],ans:"zer-",hint:"The most destructive prefix. 'Zerbrechen,' 'zerrei\u00dfen,' 'zerfallen.' Everything falls apart."},
{type:"fb",s:"Er hat mich v\u00f6llig {1}.",a:["missverstanden"],opts:["missverstanden","unverstanden","zerverstanden","verstanden"],hint:"He understood me incorrectly. The prefix for 'done wrong' plus 'verstehen.'",sSrc:"He completely misunderstood me."},
{type:"match",pairs:[{trg:"Hochdeutsch",src:"Standard German"},{trg:"Mundart",src:"dialect (literary term)"},{trg:"Umgangssprache",src:"colloquial language"},{trg:"Plattdeutsch",src:"Low German"},{trg:"Muttersprachler",src:"native speaker"}]},
{type:"mc",q:"'Ungl\u00fccklich' gegen\u00fcber 'missgl\u00fcckt' gegen\u00fcber 'zerst\u00f6rt.' Welches Wort ist am st\u00e4rksten?",opts:["zerst\u00f6rt (kaputt)","missgl\u00fcckt (ging schief)","ungl\u00fccklich (traurig)","alle gleich stark"],ans:"zerst\u00f6rt (kaputt)",hint:"From mild misfortune to a mistake to total destruction. The prefixes escalate."}
]},
{id:"deu_r34l4",title:"Wortfabrik",icon:"\ud83c\udfed",xp:15,board:true,steps:[
{type:"intro",title:"Wortfabrik",desc:"Understand how German builds words from parts. Master the rules for compound nouns. Learn productive suffixes. Decode any long German word.",goals:["Understand word formation: Bestimmungswort + Grundwort","Learn productive suffixes (-ung, -heit, -keit, -schaft, -tum)","Decode any long German word through decomposition"]},
{type:"teach",trg:"die Wortbildung",src:"word formation",pos:"noun",gender:"f",note:"Wort (word) + Bildung (formation). The science of how German\ncreates new words. Just stick words together, no limits.",example:"A: Was ist Wortbildung?\nB: Wie man neue W\u00f6rter aus alten macht.\nA: Deutsch ist der Meister der Wortbildung.\nB: Ja, man kann endlos lange W\u00f6rter bauen.",exampleSrc:"A: What is word formation?\nB: How you make new words from old ones.\nA: German is the master of word formation.\nB: Yes, you can build infinitely long words.",funFact:"Wort (word) + Bildung (formation/education). Word formation. The science of how German creates new words. German is the champion of Wortbildung: just stick words together. No hyphens needed. No limits on length."},
{type:"teach",trg:"das Bestimmungswort",src:"determining word (first part of compound)",pos:"noun",gender:"n",note:"Bestimmung (determination) + Wort (word). The first part of a\ncompound that specifies meaning. In 'Haust\u00fcr,' 'Haus' is it.",example:"A: Was ist das Bestimmungswort in 'Haustier'?\nB: 'Haus.' Es bestimmt die Art des Tieres.\nA: Und in 'Autobahn'?\nB: 'Auto.' Es sagt, welche Art Bahn.",exampleSrc:"A: What is the determining word in 'Haustier' (pet)?\nB: 'Haus.' It determines the type of animal.\nA: And in 'Autobahn'?\nB: 'Auto.' It says what kind of road.",funFact:"Bestimmung (determination) + Wort (word). The first part of a compound that specifies the meaning. In 'Haust\u00fcr' (house door), 'Haus' is the Bestimmungswort. It narrows the meaning of the second part."},
{type:"teach",trg:"das Grundwort",src:"base word (last part of compound)",pos:"noun",gender:"n",note:"Grund (base/ground) + Wort (word). Always the last part.\nDetermines gender and basic category. Grundwort = boss.",example:"A: Was ist das Grundwort in 'Haust\u00fcr'?\nB: 'T\u00fcr.' Es bestimmt das Geschlecht: die T\u00fcr.\nA: Deshalb hei\u00dft es 'die Haust\u00fcr'?\nB: Genau! Das Grundwort ist der Chef.",exampleSrc:"A: What is the base word in 'Haust\u00fcr' (house door)?\nB: 'T\u00fcr.' It determines the gender: die T\u00fcr.\nA: That is why it is 'die Haust\u00fcr'?\nB: Exactly! The base word is the boss.",funFact:"Grund (base/ground) + Wort (word). The base word in a compound, always the last part. In 'Haust\u00fcr,' 'T\u00fcr' is the Grundwort. It determines the gender and the basic category. Grundwort = boss of the compound."},
{type:"teach",trg:"die Zusammensetzung",src:"compound word",pos:"noun",gender:"f",note:"Zusammen (together) + Setzung (placing). Germany's most famous:\n'Donaudampfschifffahrtsgesellschaftskapit\u00e4n.'",example:"A: Was ist eine Zusammensetzung?\nB: Ein Wort aus zwei oder mehr Teilen.\nA: 'Bundesland' ist eine Zusammensetzung?\nB: Ja! Bund + es + Land.",exampleSrc:"A: What is a compound word?\nB: A word made from two or more parts.\nA: 'Bundesland' is a compound?\nB: Yes! Bund + es + Land.",funFact:"Zusammen (together) + Setzung (placing). A compound word. 'Donaudampfschifffahrtsgesellschaftskapit\u00e4n' is Germany's most famous Zusammensetzung. The noun form of 'zusammensetzen.'"},
{type:"teach",trg:"der Wortschatz",src:"vocabulary",pos:"noun",gender:"m",note:"Wort (word) + Schatz (treasure). Literally 'word treasure.'\nMasculine because Schatz is masculine.",example:"A: Wie gro\u00df ist dein Wortschatz?\nB: Er w\u00e4chst jeden Tag.\nA: Einen gro\u00dfen Wortschatz zu haben ist wichtig.\nB: Ja, er ist ein wahrer Schatz.",exampleSrc:"A: How large is your vocabulary?\nB: It grows every day.\nA: Having a large vocabulary is important.\nB: Yes, it is a true treasure.",funFact:"Wort (word) + Schatz (treasure). Vocabulary, literally 'word treasure.' Your Wortschatz is your treasure chest of known words. 'Einen gro\u00dfen Wortschatz haben' (to have a large vocabulary). Masculine because Schatz is masculine."},
{type:"teach",trg:"ableiten",src:"to derive",pos:"verb",gender:null,note:"Ab (from/off) + leiten (to lead/guide). Separable.\n'Das Wort leitet sich vom Lateinischen ab.'",example:"A: Woher leitet sich dieses Wort ab?\nB: Vom Lateinischen.\nA: Kann man alle W\u00f6rter ableiten?\nB: Die meisten haben einen Ursprung.",exampleSrc:"A: Where does this word derive from?\nB: From Latin.\nA: Can you derive all words?\nB: Most have an origin.",funFact:"Ab (from/off) + leiten (to lead/guide). To derive. 'Das Wort leitet sich vom Lateinischen ab.' Separable. The linguistic term for tracing a word back to its origin."},
{type:"teach",trg:"zusammensetzen",src:"to put together, to compose",pos:"verb",gender:null,note:"Zusammen (together) + setzen (to set/place). Separable.\nThe verb for German's favorite hobby: making compounds.",example:"A: Setzen wir zwei W\u00f6rter zusammen!\nB: Gut. Haus und T\u00fcr.\nA: Haust\u00fcr! Fertig.\nB: Zusammensetzen ist einfach!",exampleSrc:"A: Let us put two words together!\nB: Good. House and door.\nA: House door! Done.\nB: Putting words together is easy!",funFact:"Zusammen (together) + setzen (to set/place). To put together, to compose. 'Wir setzen zwei W\u00f6rter zusammen' (We put two words together). Separable. German's favorite hobby: making compounds."},
{type:"teach",trg:"aufteilen",src:"to divide up, to split",pos:"verb",gender:null,note:"Auf (up/apart) + teilen (to divide). Separable.\nThe opposite of zusammensetzen. Deconstruction.",example:"A: Teilen wir das Wort auf.\nB: 'Wanderweg': Wandern + Weg.\nA: Gut! Und 'Bundesland'?\nB: Bund + es + Land. Einfach!",exampleSrc:"A: Let us split the word up.\nB: 'Wanderweg': hiking + path.\nA: Good! And 'Bundesland'?\nB: Federation + linking-s + state. Easy!",funFact:"Auf (up/apart) + teilen (to divide). To divide up, to split. 'Das Wort in seine Teile aufteilen' (to divide the word into its parts). The opposite of zusammensetzen. Separable."},
{type:"teach",trg:"die Siedlung",src:"settlement, housing estate",pos:"noun",gender:"f",note:"From siedeln (to settle). The -ung suffix makes it feminine.\nGermany has Siedlungen from every era: medieval to modern.",example:"A: Was ist eine Siedlung?\nB: Ein Ort, an dem Menschen siedeln.\nA: Diese Siedlung ist aus den 1950ern.\nB: Ja, typisch f\u00fcr das Wirtschaftswunder.",exampleSrc:"A: What is a settlement?\nB: A place where people settle.\nA: This settlement is from the 1950s.\nB: Yes, typical of the economic miracle.",funFact:"From siedeln (to settle). A settlement, a housing estate. Germany has Siedlungen from every era: medieval, Gr\u00fcnderzeit, postwar. The -ung suffix makes it feminine."},
{type:"teach",trg:"das Kulturerbe",src:"cultural heritage",pos:"noun",gender:"n",note:"Kultur (culture) + Erbe (heritage). Neuter because Erbe\n(heritage) is neuter. Germany has 52 UNESCO sites.",example:"A: Ist die Altstadt Kulturerbe?\nB: Ja, sie steht unter Schutz.\nA: Kulturerbe muss man bewahren.\nB: Deshalb darf man nichts abreien.",exampleSrc:"A: Is the old town cultural heritage?\nB: Yes, it is under protection.\nA: Cultural heritage must be preserved.\nB: That is why you cannot demolish anything.",funFact:"Kultur (culture) + Erbe (heritage). Cultural heritage. 'Immaterielles Kulturerbe' (intangible cultural heritage). Germany has 52 UNESCO Welterbe sites. Neuter because Erbe (heritage) is neuter."},
{type:"teach",trg:"die Gr\u00fcnderzeit",src:"Founders' Period (1871-1914)",pos:"noun",gender:"f",note:"Gr\u00fcnder (founder) + Zeit (time). An era of rapid industrialization\nand ornate architecture. Feminine because Zeit is feminine.",example:"A: Was ist die Gr\u00fcnderzeit?\nB: Eine Epoche von 1871 bis 1914.\nA: Gr\u00fcnderzeitgeb\u00e4ude sind wundersch\u00f6n.\nB: Ja, mit verzierten Fassaden.",exampleSrc:"A: What is the Gr\u00fcnderzeit?\nB: An era from 1871 to 1914.\nA: Gr\u00fcnderzeit buildings are beautiful.\nB: Yes, with decorated facades.",funFact:"Gr\u00fcnder (founder) + Zeit (time). The Founders' Period (1871-1914). An era of rapid industrialization and ornate architecture in Germany. Gr\u00fcnderzeit buildings with their decorated facades define many German city centers."},
{type:"teach",trg:"das Wirtschaftswunder",src:"Economic Miracle",pos:"noun",gender:"n",note:"Wirtschaft (economy) + Wunder (miracle). Germany's stunning\npostwar recovery from 1948-1968. Untranslatable.",example:"A: Was war das Wirtschaftswunder?\nB: Deutschlands Aufschwung nach dem Krieg.\nA: Von Tr\u00fcmmern zur gr\u00f6\u00dften Wirtschaft Europas.\nB: In nur zwanzig Jahren!",exampleSrc:"A: What was the Economic Miracle?\nB: Germany's recovery after the war.\nA: From rubble to Europe's largest economy.\nB: In just twenty years!",funFact:"Wirtschaft (economy) + Wunder (miracle). The Economic Miracle. Germany's stunning postwar recovery from 1948-1968. From rubble to Europe's largest economy. The word captures national pride and collective effort."},
{type:"teach",trg:"das Bauwerk",src:"structure, edifice",pos:"noun",gender:"n",note:"Bau (building/construction) + Werk (work). Grander than\n'Geb\u00e4ude.' Der K\u00f6lner Dom is a Bauwerk, your garage is a Geb\u00e4ude.",example:"A: Der Dom ist ein beeindruckendes Bauwerk.\nB: Ja, ein Meisterwerk der Gotik.\nA: Welches Bauwerk ist das \u00e4lteste in Freiburg?\nB: Teile der Stadtmauer aus dem 13. Jahrhundert.",exampleSrc:"A: The cathedral is an impressive structure.\nB: Yes, a masterpiece of Gothic architecture.\nA: Which structure is the oldest in Freiburg?\nB: Parts of the city wall from the 13th century.",funFact:"Bau (building/construction) + Werk (work). A structure, an edifice. Grander than 'Geb\u00e4ude' (building). Der K\u00f6lner Dom is a Bauwerk. Your garage is a Geb\u00e4ude."},
{type:"teach",trg:"geschichtstr\u00e4chtig",src:"steeped in history",pos:"adj",gender:null,note:"Geschichte (history) + tr\u00e4chtig (pregnant/laden). Literally\n'pregnant with history.' One of German's most evocative compounds.",example:"A: Freiburg ist ein geschichtstr\u00e4chtiger Ort.\nB: Ja, \u00fcber 900 Jahre alt.\nA: Jede Stra\u00dfe ist geschichtstr\u00e4chtig.\nB: Man sp\u00fcrt die Geschichte \u00fcberall.",exampleSrc:"A: Freiburg is a place steeped in history.\nB: Yes, over 900 years old.\nA: Every street is steeped in history.\nB: You can feel the history everywhere.",funFact:"Geschichte (history) + tr\u00e4chtig (pregnant/laden with). Steeped in history, historically significant. Literally 'pregnant with history.' One of German's most evocative compound adjectives."},
{type:"teach",trg:"regionaltypisch",src:"typical of the region",pos:"adj",gender:null,note:"Regional + typisch (typical). Describes anything authentically\nlocal. 'Regionaltypische K\u00fcche' (regional cuisine).",example:"A: Was ist regionaltypisch f\u00fcr Freiburg?\nB: Sp\u00e4tzle, Schwarzw\u00e4lder Kirschtorte, Wein.\nA: Regionaltypisches Essen ist das Beste.\nB: Ja, immer frisch und lokal.",exampleSrc:"A: What is typical of the region in Freiburg?\nB: Sp\u00e4tzle, Black Forest cake, wine.\nA: Regional food is the best.\nB: Yes, always fresh and local.",funFact:"Regional + typisch (typical). Typical of the region, regionally characteristic. 'Regionaltypische K\u00fcche' (regional cuisine). A compound adjective that describes anything authentically local."},
{type:"teach",trg:"traditionsbewusst",src:"tradition-conscious",pos:"adj",gender:null,note:"Tradition + bewusst (conscious/aware). Mindful of tradition.\nGermans value Traditionsbewusstsein alongside innovation.",example:"A: Ist Freiburg traditionsbewusst?\nB: Ja, sehr. Die Altstadt wird gepflegt.\nA: Traditionsbewusste D\u00f6rfer sind charmant.\nB: Ja, sie bewahren ihre Identit\u00e4t.",exampleSrc:"A: Is Freiburg tradition-conscious?\nB: Yes, very. The old town is well-maintained.\nA: Tradition-conscious villages are charming.\nB: Yes, they preserve their identity.",funFact:"Tradition + bewusst (conscious/aware). Tradition-conscious, mindful of tradition. 'Ein traditionsbewusstes Dorf' (a village mindful of its traditions). Germans value Traditionsbewusstsein alongside innovation."},
{type:"teach",trg:"daher",src:"therefore, from there",pos:"adv",gender:null,note:"Da (there) + her (from). Both causal ('Daher ist es wichtig')\nand directional ('Er kommt von daher'). Context decides.",example:"A: Freiburg liegt im S\u00fcden. Daher ist es warm.\nB: Ja, daher kommen auch die Weinberge.\nA: Daher ist die Stadt so beliebt.\nB: Warm, sch\u00f6n und voller Kultur.",exampleSrc:"A: Freiburg lies in the south. Therefore it is warm.\nB: Yes, that is also where the vineyards come from.\nA: That is why the city is so popular.\nB: Warm, beautiful, and full of culture.",funFact:"Da (there) + her (from). Therefore, from there. Both a causal adverb ('Daher ist es wichtig') and a directional one ('Er kommt von daher'). Context determines meaning. Same as 'deshalb' when causal."},
{type:"teach",trg:"gern",src:"gladly, with pleasure",pos:"adv",gender:null,note:"A modal adverb. 'Ich wandere gern' (I like to hike).\n'Gern geschehen' (You're welcome, literally 'gladly done').",example:"A: Wanderst du gern?\nB: Ja, sehr gern!\nA: Gern geschehen!\nB: Danke, du bist sehr nett.",exampleSrc:"A: Do you like to hike?\nB: Yes, very much!\nA: You're welcome!\nB: Thanks, you are very kind.",funFact:"'Gladly, with pleasure.' 'Ich wandere gern' (I like to hike). 'Gern geschehen' (You're welcome, literally 'gladly done'). One of the most-used small words in German."},
{type:"tip",title:"Wortbildung: Wie Deutsch W\u00f6rter baut",text:"Rule 1: Bestimmungswort + Grundwort = compound noun.\n'Haus' + 'T\u00fcr' = 'Haust\u00fcr.' The Grundwort (last part) determines the gender: die T\u00fcr, therefore die Haust\u00fcr.\n\nRule 2: Sometimes a linking element (Fugenelement) appears:\nArbeit-s-platz, Freundschaft-s-ring, Bundesland.\n\nRule 3: Suffixes create new words:\n-ung = feminine nouns (Bildung, Siedlung)\n-heit/-keit = feminine abstract nouns (Freiheit, M\u00f6glichkeit)\n-schaft = feminine collective nouns (Freundschaft)\n-tum = neuter nouns (Wachstum, Altertum)\n\nRule 4: Adjective suffixes:\n-lich = freundlich, landschaftlich\n-bar = machbar, trinkbar\n-ig = traurig, giftig\n-sam = sparsam, einsam",deepDive:{title:"Wortbildung: compound rules and linking elements",text:"Linking elements (Fugenelemente) follow patterns but have exceptions. The most common is -s-: Arbeit-s-platz, Geburt-s-tag, Wirtschaft-s-wunder. Feminine nouns with -ung, -heit, -keit, -schaft, -tion almost always take -s-.\n\nOther linking elements: -n- (Blume-n-vase), -en- (Frau-en-haus), -er- (Kind-er-garten), -e- (Hund-e-h\u00fctte).\n\nThe Grundwort always wins for gender. 'Die Haust\u00fcr' (feminine, because T\u00fcr is feminine). 'Der Wanderweg' (masculine, because Weg is masculine). This rule has no exceptions.\n\nLong compounds are read right-to-left: identify the Grundwort first, then add the Bestimmungsw\u00f6rter as modifiers."}},
{type:"tip",title:"Lange W\u00f6rter entschl\u00fcsseln",text:"Strategy: read from right to left.\n\nThe Grundwort (far right) gives the category.\nThe Bestimmungswort (left) specifies it.\n\nExample: 'Bundestagsabgeordneter'\nAbgeordneter (delegate) + Bundestag (federal parliament)\n= member of the federal parliament.\n\nYou already know both halves. The compound is just the packaging.\n\nAnother example: 'Geschwindigkeitsbegrenzung'\nBegrenzung (limit) + Geschwindigkeit (speed)\n= speed limit. Easy!"},
{type:"mc",q:"Was bestimmt das grammatische Geschlecht eines zusammengesetzten Nomens?",opts:["Der l\u00e4ngste Teil","Das Bestimmungswort (erster Teil)","Das Grundwort (letzter Teil)","Der h\u00e4ufigste Teil"],ans:"Das Grundwort (letzter Teil)",hint:"The base word is the boss. It determines gender and core meaning."},
{type:"fb",s:"Die M\u00f6glichkeit kommt von 'moglich' plus die Endung {1}.",a:["-keit"],opts:["-keit","-heit","-ung","-schaft"],hint:"This suffix forms feminine abstract nouns from adjectives ending in -lich or -ig.",sSrc:"'M\u00f6glichkeit' comes from 'm\u00f6glich' plus the ending -keit."},
{type:"mc",q:"Wirtschaft + Wunder = Wirtschaftswunder. Welches Fugenelement erscheint?",opts:["-s- (Fugen-s)","-n- (Fugen-n)","kein Fugen-element (\u2014)","-er- (Fugen-er)"],ans:"kein Fugen-element (\u2014)",hint:"Some words join directly without a linking element. Here the two parts simply meet."},
{type:"drag_fill",s:"Geschichtstr\u00e4chtig = {1} + {2}. Es bedeutet: voll von {3}.",blanks:{"1":"Geschichte","2":"tr\u00e4chtig","3":"Geschichte"},pool:["Geschichte","tr\u00e4chtig","Geschichten","traurig","Tradition","Kultur"],hint:"Decompose the compound adjective into its two elements. The second element comes from a word meaning laden or pregnant with something. Both elements appear among the pool options.",sSrc:"Geschichtstr\u00e4chtig = Geschichte + tr\u00e4chtig. It means: full of history."},
{type:"match",pairs:[{trg:"-ung",src:"feminines Nomen (Bildung)"},{trg:"-heit",src:"feminines Abstraktum (Freiheit)"},{trg:"-lich",src:"Adjektiv (freundlich)"},{trg:"-bar",src:"Adjektiv (machbar)"},{trg:"-tum",src:"neutrales Nomen (Wachstum)"}]}
]},
{id:"deu_r34l5",title:"Erst wann, dann warum",icon:"\uD83D\uDCCD",xp:15,board:true,steps:[
{type:"intro",title:"Erst wann, dann warum",desc:"Master German sentence order for adverbs. Learn the TeKaMoLo rule. Explore Freiburg's culture and traditions.",goals:["Lerne die TeKaMoLo-Regel f\u00fcr Adverbien","Entdecke Freiburgs Kultur und Traditionen","Kombiniere alle drei Grammatikkonstrukte"]},
{type:"story",speaker:"narrator",mood:"warm",trg:"Freiburg. Die Altstadt \u00f6ffnet sich vor ihnen wie ein Bilderbuch. Schmale Kopfsteinpflasterstra\u00dfen. Die ber\u00fchmten B\u00e4chle flie\u00dfen entlang der Rinnen. Fachwerkh\u00e4user lehnen sich aneinander. Der M\u00fcnsterturm ragt \u00fcber alles hinaus.",src:"Freiburg. The old town opens before them like a storybook. Narrow cobblestone streets. The famous B\u00e4chle (tiny water channels) run along the gutters. Half-timbered houses lean against each other. The cathedral tower rises above everything."},
{type:"story",speaker:"mia",mood:"enthusiastic",trg:"Die B\u00e4chle! Wer hineintritt, muss einen Freiburger heiraten. Vorsicht, Verumius!",src:"The B\u00e4chle! Whoever steps in must marry a Freiburger. Careful, Verumius!"},
{type:"story",speaker:"verumius",mood:"amused",trg:"Dann passe ich auf. Ich m\u00f6chte erst die Stadt erkunden, bevor ich heirate.",src:"Then I will be careful. I want to explore the city first, before I get married."},
{type:"story",speaker:"hildi",mood:"lecturing",trg:"Verumius, im Deutschen gibt es eine Reihenfolge f\u00fcr Adverbien: zuerst WANN, dann WARUM, dann WIE, dann WO.",src:"Verumius, in German there is an order for adverbs: first WHEN, then WHY, then HOW, then WHERE."},
{type:"story",speaker:"verumius",mood:"confused",trg:"Eine Reihenfolge? F\u00fcr Adverbien?",src:"An order? For adverbs?"},
{type:"story",speaker:"hildi",mood:"patient",trg:"TeKaMoLo. Temporal, Kausal, Modal, Lokal. 'Ich fahre morgen wegen der Arbeit gern nach Freiburg.' Wann, warum, wie, wohin.",src:"TeKaMoLo. Temporal, Causal, Modal, Local. 'I gladly drive to Freiburg tomorrow because of work.' When, why, how, where."},
{type:"teach",trg:"das Naturschutzgebiet",src:"nature reserve",pos:"noun",gender:"n",note:"Natur (nature) + Schutz (protection) + Gebiet (area).\nThree nouns welded into one protected area.",example:"A: Ist das ein Naturschutzgebiet?\nB: Ja, der Schwarzwald hat viele davon.\nA: Darf man dort wandern?\nB: Ja, aber nur auf den markierten Wegen.",exampleSrc:"A: Is that a nature reserve?\nB: Yes, the Black Forest has many of them.\nA: Can you hike there?\nB: Yes, but only on the marked trails.",funFact:"Natur (nature) + Schutz (protection) + Gebiet (area). Germany has over 8,700 Naturschutzgebiete covering 6.3% of the country. The Black Forest near Freiburg contains several. Three nouns, one protected area."},
{type:"teach",trg:"das Fachwerk",src:"half-timbered construction",pos:"noun",gender:"n",note:"Fach (compartment) + Werk (work). The iconic German\nbuilding style with visible wooden frames.",example:"A: Was ist Fachwerk?\nB: Eine Bauweise mit sichtbaren Holzbalken.\nA: Gibt es viel Fachwerk in Freiburg?\nB: Ja, die ganze Altstadt ist voll davon.",exampleSrc:"A: What is Fachwerk?\nB: A building style with visible wooden beams.\nA: Is there a lot of Fachwerk in Freiburg?\nB: Yes, the whole old town is full of it.",funFact:"Fach (compartment/panel) + Werk (work). Fachwerkh\u00e4user are the iconic German buildings with visible wooden frames and white plaster between. Freiburg, Rothenburg, and Quedlinburg are Fachwerk capitals."},
{type:"teach",trg:"die Gemeinde",src:"municipality, community",pos:"noun",gender:"f",note:"From 'gemein' (common/shared). The smallest\nadministrative unit in Germany.",example:"A: Wie gro\u00df ist diese Gemeinde?\nB: Etwa 5.000 Einwohner.\nA: Hat jede Gemeinde einen B\u00fcrgermeister?\nB: Ja, das ist Pflicht.",exampleSrc:"A: How big is this municipality?\nB: About 5,000 residents.\nA: Does every municipality have a mayor?\nB: Yes, that is mandatory.",funFact:"From 'gemein' (common/shared). Die Gemeinde is the smallest administrative unit in Germany. Every village is a Gemeinde. Also means a church congregation."},
{type:"teach",trg:"die Hanse",src:"the Hanseatic League",pos:"noun",gender:"f",note:"From Middle Low German 'hanse' (group of merchants).\nA medieval trade alliance of northern German cities.",example:"A: Was war die Hanse?\nB: Ein B\u00fcndnis norddeutscher Kaufleute.\nA: Welche St\u00e4dte geh\u00f6rten dazu?\nB: Hamburg, Bremen, L\u00fcbeck, Rostock.",exampleSrc:"A: What was the Hanse?\nB: An alliance of northern German merchants.\nA: Which cities belonged to it?\nB: Hamburg, Bremen, L\u00fcbeck, Rostock.",funFact:"From Middle Low German 'hanse' (group of merchants). The Hanseatic League dominated Baltic trade for centuries. Hamburg still calls itself 'Freie und Hansestadt Hamburg.'"},
{type:"teach",trg:"die Kulturveranstaltung",src:"cultural event",pos:"noun",gender:"f",note:"Kultur (culture) + Veranstaltung (event). Concerts,\ntheater, exhibitions. A transparent compound.",example:"A: Gibt es heute eine Kulturveranstaltung?\nB: Ja, ein Konzert im M\u00fcnsterplatz.\nA: Freiburg hat viele Kulturveranstaltungen.\nB: Fast jeden Abend passiert etwas.",exampleSrc:"A: Is there a cultural event today?\nB: Yes, a concert at the M\u00fcnsterplatz.\nA: Freiburg has many cultural events.\nB: Almost every evening something happens.",funFact:"Kultur (culture) + Veranstaltung (event). Concerts, theater, exhibitions. 'Freiburg hat viele Kulturveranstaltungen.' The compound is long but transparent: a culture + event."},
{type:"teach",trg:"der Stammtisch",src:"regulars' table at a pub",pos:"noun",gender:"m",note:"Stamm (trunk/regular) + Tisch (table). A reserved table\nwhere the same group meets weekly.",example:"A: Was ist ein Stammtisch?\nB: Ein Tisch f\u00fcr die Stammg\u00e4ste.\nA: Hast du einen Stammtisch?\nB: Ja, jeden Donnerstag im Gasthaus.",exampleSrc:"A: What is a Stammtisch?\nB: A table for the regulars.\nA: Do you have a Stammtisch?\nB: Yes, every Thursday at the pub.",funFact:"Stamm (trunk/regular) + Tisch (table). A reserved table where the same group meets weekly. Stammtisch culture is quintessentially German: beer, discussion, community. Some Stammtische have existed for generations."},
{type:"teach",trg:"das Volksfest",src:"folk festival",pos:"noun",gender:"n",note:"Volk (people) + Fest (festival). Oktoberfest is the\nmost famous, but every region has its own.",example:"A: Warst du schon auf einem Volksfest?\nB: Ja, auf dem M\u00fcnchner Oktoberfest.\nA: Das ist das gr\u00f6\u00dfte Volksfest der Welt.\nB: Millionen Besucher jedes Jahr.",exampleSrc:"A: Have you been to a folk festival?\nB: Yes, to the Munich Oktoberfest.\nA: That is the biggest folk festival in the world.\nB: Millions of visitors every year.",funFact:"Volk (people) + Fest (festival). Oktoberfest is the most famous Volksfest, but every region has its own: Cannstatter Wasen, Hamburger Dom, D\u00fcrkheimer Wurstmarkt. Neuter because Fest is neuter."},
{type:"teach",trg:"der Jahrmarkt",src:"fair, annual market",pos:"noun",gender:"m",note:"Jahr (year) + Markt (market). Originally a yearly\ntrading event. Now: rides, cotton candy, games.",example:"A: Gehen wir auf den Jahrmarkt?\nB: Ja, ich liebe Jahrm\u00e4rkte!\nA: Riesenrad oder Achterbahn?\nB: Zuerst Riesenrad, danach Achterbahn.",exampleSrc:"A: Shall we go to the fair?\nB: Yes, I love fairs!\nA: Ferris wheel or roller coaster?\nB: First ferris wheel, then roller coaster.",funFact:"Jahr (year) + Markt (market). Originally a yearly trading event in medieval towns. Now: rides, cotton candy, carnival games. Different from a Volksfest (which focuses on beer and tradition)."},
{type:"teach",trg:"der Fasching",src:"carnival (southern German term)",pos:"noun",gender:"m",note:"From Middle High German 'vastschang' (the last drink\nbefore Lent). Same as Karneval, different name.",example:"A: Feiert ihr Fasching?\nB: Ja, in S\u00fcddeutschland sagt man Fasching.\nA: Und im Rheinland?\nB: Dort hei\u00dft es Karneval.",exampleSrc:"A: Do you celebrate Fasching?\nB: Yes, in southern Germany we say Fasching.\nA: And in the Rhineland?\nB: There it is called Karneval.",funFact:"From Middle High German 'vastschang' (the last drink before Lent). Called Fasching in southern Germany, Karneval in the Rhineland, and Fastnacht in southwestern Germany. Same celebration, three names."},
{type:"teach",trg:"entdecken",src:"to discover",pos:"verb",gender:null,note:"Ent- (un-) + decken (to cover). To uncover, to discover.\nNot separable. Columbus entdeckte Amerika.",example:"A: Was hast du in Freiburg entdeckt?\nB: Ein tolles Caf\u00e9 in der Altstadt.\nA: Ich entdecke gern neue Orte.\nB: Ich auch. Entdecken macht gl\u00fccklich.",exampleSrc:"A: What did you discover in Freiburg?\nB: A great caf\u00e9 in the old town.\nA: I like to discover new places.\nB: Me too. Discovering makes you happy.",funFact:"Ent- (un-) + decken (to cover). To discover, literally to uncover. Columbus 'entdeckte' America. You 'entdecken' a hidden caf\u00e9. The ent- prefix reverses the covering. Not separable."},
{type:"teach",trg:"flanieren",src:"to stroll leisurely",pos:"verb",gender:null,note:"From French 'fl\u00e2ner' (to stroll). A civilized,\nunhurried walk through a beautiful place.",example:"A: Sollen wir durch die Altstadt flanieren?\nB: Ja, bei diesem Wetter perfekt.\nA: Flanieren ist besser als hetzen.\nB: Ganz entspannt, ohne Eile.",exampleSrc:"A: Shall we stroll through the old town?\nB: Yes, perfect in this weather.\nA: Strolling is better than rushing.\nB: Completely relaxed, without hurry.",funFact:"From French 'fl\u00e2ner' (to stroll). 'Durch die Altstadt flanieren' (to stroll through the old town). Borrowed from French with the original meaning intact. A civilized, unhurried walk."},
{type:"teach",trg:"einkehren",src:"to stop in at an inn",pos:"verb",gender:null,note:"Ein (in) + kehren (to turn). To stop in for food\nand drink. Separable. From the hiking tradition.",example:"A: Sollen wir irgendwo einkehren?\nB: Ja, in dem Gasthaus dort.\nA: Nach dem Wandern kehrt man gern ein.\nB: Ein Bier und eine Brezel, bitte!",exampleSrc:"A: Shall we stop in somewhere?\nB: Yes, at that inn over there.\nA: After hiking you like to stop in.\nB: A beer and a pretzel, please!",funFact:"Ein (in) + kehren (to turn). To stop in at an inn or restaurant. Separable. A word from the hiking tradition: after a long walk, you einkehren for food and drink."},
{type:"teach",trg:"vorbeischauen",src:"to drop by, to stop in briefly",pos:"verb",gender:null,note:"Vorbei (past/by) + schauen (to look). Separable.\nMore casual than 'besuchen.' South German style.",example:"A: Schau doch mal vorbei!\nB: Gern, wann passt es dir?\nA: Heute Nachmittag?\nB: Perfekt, ich schaue um drei vorbei.",exampleSrc:"A: Drop by sometime!\nB: Gladly, when suits you?\nA: This afternoon?\nB: Perfect, I will drop by at three.",funFact:"Vorbei (past/by) + schauen (to look). To drop by, to stop in briefly. Separable. 'Schau mal vorbei!' (Drop by sometime!). More casual than 'besuchen.' The South German version of 'vorbeikommen.'"},
{type:"teach",trg:"kosmopolitisch",src:"cosmopolitan",pos:"adj",gender:null,note:"From Greek 'kosmopolites' (citizen of the world).\nSame word internationally. Freiburg is surprisingly so.",example:"A: Ist Freiburg kosmopolitisch?\nB: Ja, wegen der Universit\u00e4t.\nA: Studenten aus aller Welt.\nB: Und die N\u00e4he zu Frankreich und der Schweiz.",exampleSrc:"A: Is Freiburg cosmopolitan?\nB: Yes, because of the university.\nA: Students from all over the world.\nB: And the proximity to France and Switzerland.",funFact:"From Greek 'kosmopolites' (citizen of the world). Cosmopolitan. Freiburg, despite its size, is surprisingly kosmopolitisch thanks to its university and proximity to France and Switzerland."},
{type:"teach",trg:"abgelegen",src:"remote, secluded",pos:"adj",gender:null,note:"Ab (away) + gelegen (situated). Past participle of\n'abliegen' used as adjective. Far from everything.",example:"A: Das Dorf ist ziemlich abgelegen.\nB: Ja, keine Autobahn, kein Bahnhof.\nA: Aber die Landschaft ist wundersch\u00f6n.\nB: Abgelegen, aber atemberaubend.",exampleSrc:"A: The village is quite remote.\nB: Yes, no highway, no train station.\nA: But the landscape is wonderful.\nB: Remote, but breathtaking.",funFact:"Ab (away) + gelegen (situated). 'Ein abgelegenes Dorf im Schwarzwald' (a remote village in the Black Forest). The past participle of 'abliegen' used as an adjective. Far away from everything."},
{type:"teach",trg:"irgendwie",src:"somehow",pos:"adv",gender:null,note:"Irgend (some-) + wie (how). A modal adverb.\nPart of the irgend- family: -wann, -wo, -wie.",example:"A: Irgendwie schaffen wir das.\nB: Bist du sicher?\nA: Ja, irgendwie geht es immer.\nB: Dein Optimismus ist ansteckend.",exampleSrc:"A: Somehow we will manage.\nB: Are you sure?\nA: Yes, somehow it always works out.\nB: Your optimism is contagious.",funFact:"Irgend (some-) + wie (how). Somehow. A modal adverb. 'Irgendwie schaffen wir das.' The 'irgend-' family: irgendwann (sometime), irgendwo (somewhere), irgendwie (somehow)."},
{type:"teach",trg:"m\u00f6glicherweise",src:"possibly, perhaps",pos:"adv",gender:null,note:"M\u00f6glich (possible) + er + weise (way/manner). A formal\nmodal adverb. More formal than 'vielleicht.'",example:"A: Regnet es morgen?\nB: M\u00f6glicherweise, laut Wetterbericht.\nA: Dann nehmen wir Regenschirme mit.\nB: M\u00f6glicherweise brauchen wir sie nicht.",exampleSrc:"A: Will it rain tomorrow?\nB: Possibly, according to the weather report.\nA: Then we will take umbrellas.\nB: Possibly we won't need them.",funFact:"M\u00f6glich (possible) + er + weise (way/manner). Possibly, perhaps. A formal modal adverb. More formal than 'vielleicht.' The -erweise ending signals manner."},
{type:"teach",trg:"vermutlich",src:"presumably, probably",pos:"adv",gender:null,note:"From 'vermuten' (to suspect/assume). Expresses educated\nguessing. Stronger than 'vielleicht.'",example:"A: Kommt Lukas p\u00fcnktlich?\nB: Vermutlich nicht, er ist immer sp\u00e4t.\nA: Vermutlich hat er sich verfahren.\nB: Das w\u00e4re nicht das erste Mal.",exampleSrc:"A: Will Lukas arrive on time?\nB: Presumably not, he is always late.\nA: Presumably he got lost.\nB: That would not be the first time.",funFact:"From 'vermuten' (to suspect/assume). Presumably, probably. 'Vermutlich kommt er sp\u00e4ter.' Expresses educated guessing. Stronger than 'vielleicht' (maybe) but weaker than 'wahrscheinlich' (likely)."},
{type:"tip",title:"TeKaMoLo: Die Reihenfolge der Adverbien",text:"When a sentence has multiple adverbs, German orders them like this:\n\nTe = Temporal (when?)\nKa = Kausal (why?)\nMo = Modal (how?)\nLo = Lokal (where/to where?)\n\nExample: 'Ich fahre morgen(Te) wegen des Regens(Ka) lieber(Mo) nach Freiburg(Lo).'\n\nMemory aid: 'Tea, Coffee, Poppy, Lotto' (Tee, Kaffee, Mohn, Lotto).\n\nThis is the default order, not an absolute rule. Emphasis can shift elements, but TeKaMoLo sounds most natural.",deepDive:{title:"TeKaMoLo in practice",text:"TeKaMoLo is the default adverb order in German middle field (Mittelfeld) sentences. When multiple adverbs compete for position, this order sounds most natural to native speakers.\n\nTemporal: morgen, gestern, heute, oft, manchmal\nKausal: wegen, deshalb, deswegen, aus Freude\nModal: gern, leider, irgendwie, vermutlich\nLokal: dort, hier, nach Freiburg, in der Altstadt\n\nExample: 'Wir sind gestern(Te) aus Neugier(Ka) gem\u00fctlich(Mo) durch die Altstadt(Lo) flaniert.'\n\nNote: Pronouns and known information tend to move left, new information moves right. TeKaMoLo applies when all else is equal."}},
{type:"mc",q:"Welcher Satz folgt der TeKaMoLo-Regel korrekt?",opts:["Ich fahre gern morgen nach Freiburg wegen der Arbeit","Ich fahre nach Freiburg morgen wegen der Arbeit gern","Ich fahre wegen der Arbeit nach Freiburg morgen gern","Ich fahre morgen wegen der Arbeit gern nach Freiburg"],ans:"Ich fahre morgen wegen der Arbeit gern nach Freiburg",hint:"Te(mporal) Ka(usal) Mo(dal) Lo(kal). First WHEN, then WHY, then HOW, then WHERE TO.",sSrc:"Which sentence follows the TeKaMoLo rule correctly?"},
{type:"fb",s:"Er ist gestern {1} Kopfschmerzen leider nicht nach Freiburg gefahren.",a:["wegen"],opts:["wegen","trotz","nach","in"],hint:"A kausal element (WHY) between temporal (gestern) and modal (leider).",sSrc:"He did not go to Freiburg yesterday because of a headache, unfortunately."},
{type:"drag_fill",s:"Wir sind {1} {2} {3} durch die Altstadt {4}.",blanks:{"1":"gestern","2":"aus Neugier","3":"gem\u00fctlich","4":"flaniert"},pool:["gestern","aus Neugier","gem\u00fctlich","flaniert","morgen","schnell"],hint:"When? Yesterday. Why? Out of curiosity. How? Comfortably. The verb goes at the end.",sSrc:"We strolled through the old town yesterday out of curiosity comfortably."},
{type:"mc",q:"Naturschutzgebiet: Was ist das Grundwort, und welches Pr\u00e4fix k\u00f6nnte 'nat\u00fcrlich' verneinen?",opts:["Natur ist Grundwort, zer- verneint","Gebiet ist Grundwort, un- verneint: unnat\u00fcrlich","Schutz ist Grundwort, miss- verneint","Naturschutz ist Grundwort, ver- verneint"],ans:"Gebiet ist Grundwort, un- verneint: unnat\u00fcrlich",hint:"Identify which part of the compound gives it its gender. Then ask: which negation prefix creates the mildest opposite of an adjective?",sSrc:"Naturschutzgebiet: What is the base word, and which prefix could negate 'nat\u00fcrlich'?"},
{type:"match",pairs:[{trg:"Stammtisch",src:"regulars' table at a pub"},{trg:"Fasching",src:"carnival (southern term)"},{trg:"Volksfest",src:"folk festival"},{trg:"Naturschutzgebiet",src:"nature reserve"},{trg:"Fachwerk",src:"half-timbered construction"}]}
]},
{id:"deu_r34l6",title:"Konzert in Freiburg",icon:"\uD83C\uDFB5",xp:15,board:true,steps:[
{type:"intro",title:"Konzert in Freiburg",desc:"Experience Lukas's musical comeback. Discover Germany's geographic and cultural diversity. Practice all three grammar constructs together.",goals:["Experience Lukas's concert with 'Fernweh'","Discover Germany's geographic diversity","Combine TeKaMoLo, word formation, and negation prefixes"]},
{type:"story",speaker:"narrator",mood:"warm",trg:"Abend in Freiburg. Ein kleiner Club in der Altstadt. Lichterketten. Die B\u00fchne ist winzig, aber der Sound ist gro\u00df. Lukas' neue Band: Schlagzeug, Bass, Keyboards und Lukas an Gitarre und Gesang. Sie hei\u00dfen 'Fernweh.'",src:"Evening in Freiburg. A small venue in the old town. Fairy lights. The stage is tiny but the sound is big. Lukas's new band: drums, bass, keys, and Lukas on guitar and vocals. They are called 'Fernweh.'"},
{type:"story",speaker:"narrator",mood:"proud",trg:"Die Musik beginnt. Sie ist gut. Richtig gut. Lukas spielt mit geschlossenen Augen, verloren im Klang. Das Publikum lehnt sich vor. Mia filmt mit dem Handy. Hildi wippt mit dem Fu\u00df. Verumius denkt: Er hat seinen Weg zur\u00fcckgefunden.",src:"The music starts. It is good. Really good. Lukas plays with his eyes closed, lost in the sound. The crowd leans in. Mia records on her phone. Hildi taps her foot. Verumius thinks: he found his way back."},
{type:"story",speaker:"mia",mood:"happy",trg:"Er ist richtig gut geworden. Die neue Band passt zu ihm.",src:"He has become really good. The new band suits him."},
{type:"story",speaker:"hildi",mood:"warm",trg:"Nicht schlecht. Ich h\u00e4tte nicht gedacht, dass mir so etwas gef\u00e4llt.",src:"Not bad. I would not have thought I would like something like this."},
{type:"story",speaker:"verumius",mood:"happy",trg:"Lukas hat \u00fcberall in Deutschland gespielt und ist viel herumgekommen. Deswegen kennt er jede Region.",src:"Lukas has played everywhere in Germany and has traveled a lot. That is why he knows every region."},
{type:"teach",trg:"die Landeshauptstadt",src:"state capital",pos:"noun",gender:"f",note:"Land (state) + Haupt (main) + Stadt (city).\nThree nouns in one capital city.",example:"A: Was ist die Landeshauptstadt von Bayern?\nB: M\u00fcnchen.\nA: Und von Baden-W\u00fcrttemberg?\nB: Stuttgart.",exampleSrc:"A: What is the state capital of Bavaria?\nB: Munich.\nA: And of Baden-W\u00fcrttemberg?\nB: Stuttgart.",funFact:"Land (state) + Haupt (main) + Stadt (city). Each of Germany's 16 Bundesl\u00e4nder has its Landeshauptstadt. Munich for Bavaria, Stuttgart for Baden-W\u00fcrttemberg, Dresden for Saxony. Three nouns in one capital."},
{type:"teach",trg:"die K\u00fcstenregion",src:"coastal region",pos:"noun",gender:"f",note:"K\u00fcste (coast) + Region. Germany's K\u00fcstenregionen\nstretch along the North Sea and Baltic Sea.",example:"A: Warst du schon in einer K\u00fcstenregion?\nB: Ja, an der Ostsee.\nA: Wie ist es dort?\nB: Flach, windig und wundersch\u00f6n.",exampleSrc:"A: Have you been to a coastal region?\nB: Yes, on the Baltic Sea.\nA: What is it like there?\nB: Flat, windy, and beautiful.",funFact:"K\u00fcste (coast) + Region. Germany's K\u00fcstenregionen stretch along the North Sea and Baltic Sea. Flat, windy, and home to Plattdeutsch speakers. Feminine because Region is feminine."},
{type:"teach",trg:"Norddeutschland",src:"Northern Germany",pos:"noun",gender:"n",note:"Nord (north) + Deutschland. Hamburg, Bremen,\nSchleswig-Holstein. Flat, maritime, reserved.",example:"A: Wie ist Norddeutschland?\nB: Flach und windig.\nA: Und die Menschen?\nB: Etwas reservierter als im S\u00fcden.",exampleSrc:"A: What is Northern Germany like?\nB: Flat and windy.\nA: And the people?\nB: A bit more reserved than in the south.",funFact:"Nord (north) + Deutschland. Hamburg, Bremen, Schleswig-Holstein, Niedersachsen, Mecklenburg-Vorpommern. Flat landscapes, fishing villages, maritime culture. Neuter because Deutschland is neuter."},
{type:"teach",trg:"S\u00fcddeutschland",src:"Southern Germany",pos:"noun",gender:"n",note:"S\u00fcd (south) + Deutschland. Bavaria, Baden-W\u00fcrttemberg.\nAlps, beer gardens, stronger dialects.",example:"A: Was ist typisch f\u00fcr S\u00fcddeutschland?\nB: Berge, Bier und Brezeln.\nA: Und die Dialekte?\nB: Viel st\u00e4rker als im Norden.",exampleSrc:"A: What is typical of Southern Germany?\nB: Mountains, beer, and pretzels.\nA: And the dialects?\nB: Much stronger than in the north.",funFact:"S\u00fcd (south) + Deutschland. Bavaria, Baden-W\u00fcrttemberg. Alps, beer gardens, Baroque churches, stronger dialects. Everything below the 'Wei\u00dfwurst-\u00c4quator.'"},
{type:"teach",trg:"das Mittelgebirge",src:"low mountain range",pos:"noun",gender:"n",note:"Mittel (middle) + Gebirge (mountain range). Germany's\nbackbone between 500 and 1,500 meters.",example:"A: Was ist ein Mittelgebirge?\nB: Ein Gebirge mittlerer H\u00f6he.\nA: Der Schwarzwald ist eins?\nB: Ja, auch der Harz und das Erzgebirge.",exampleSrc:"A: What is a Mittelgebirge?\nB: A mountain range of medium height.\nA: The Black Forest is one?\nB: Yes, also the Harz and the Erzgebirge.",funFact:"Mittel (middle) + Gebirge (mountain range). Germany's Mittelgebirge (Harz, Schwarzwald, Erzgebirge) are between 500 and 1,500m. Not the Alps, not the lowlands. The backbone of central Germany."},
{type:"teach",trg:"die Tiefebene",src:"lowland plain",pos:"noun",gender:"f",note:"Tief (low/deep) + Ebene (plain). The Norddeutsche\nTiefebene stretches from the Netherlands to Poland.",example:"A: Warum ist Norddeutschland so flach?\nB: Wegen der Tiefebene.\nA: Die Norddeutsche Tiefebene?\nB: Ja, perfekt f\u00fcr Windkraft und Radfahren.",exampleSrc:"A: Why is Northern Germany so flat?\nB: Because of the lowland plain.\nA: The North German Plain?\nB: Yes, perfect for wind power and cycling.",funFact:"Tief (low/deep) + Ebene (plain). The Norddeutsche Tiefebene stretches from the Netherlands to Poland. Flat as a table. Perfect for wind turbines and cycling."},
{type:"teach",trg:"die Flusslandschaft",src:"river landscape",pos:"noun",gender:"f",note:"Fluss (river) + Landschaft (landscape). The Rhine,\nElbe, Danube, and Mosel shaped Germany's valleys.",example:"A: Welche Flusslandschaft ist am sch\u00f6nsten?\nB: Das Rheintal, mit Burgen und Weinbergen.\nA: Die Mosel ist auch wundersch\u00f6n.\nB: Jede Flusslandschaft hat ihren Charme.",exampleSrc:"A: Which river landscape is the most beautiful?\nB: The Rhine Valley, with castles and vineyards.\nA: The Mosel is also wonderful.\nB: Every river landscape has its charm.",funFact:"Fluss (river) + Landschaft (landscape). The Rhine, Elbe, Danube, and Mosel have shaped Germany's Flusslandschaften. Castles on cliffs, vineyards on slopes, trade routes in the valleys."},
{type:"teach",trg:"das Industriegebiet",src:"industrial area",pos:"noun",gender:"n",note:"Industrie + Gebiet (area). The Ruhrgebiet was Germany's\nindustrial heartland. Now a cultural region.",example:"A: Was ist das Ruhrgebiet?\nB: Ein gro\u00dfes Industriegebiet.\nA: Gibt es dort nur Fabriken?\nB: Nein, heute auch Museen und Parks.",exampleSrc:"A: What is the Ruhrgebiet?\nB: A large industrial area.\nA: Are there only factories there?\nB: No, today also museums and parks.",funFact:"Industrie + Gebiet (area). The Ruhrgebiet (Ruhr area) was Germany's industrial heartland: coal, steel, factories. Now transformed into a cultural region with museums and parks."},
{type:"teach",trg:"die Zugspitze",src:"Zugspitze (Germany's highest peak)",pos:"noun",gender:"f",note:"Zug (train/pull) + Spitze (peak). Germany's highest\nmountain at 2,962 meters, on the Austrian border.",example:"A: Wie hoch ist die Zugspitze?\nB: 2.962 Meter.\nA: Kann man dort Ski fahren?\nB: Ja, sogar im Fr\u00fchling noch.",exampleSrc:"A: How high is the Zugspitze?\nB: 2,962 meters.\nA: Can you ski there?\nB: Yes, even in spring still.",funFact:"Zug (train/pull/draft) + Spitze (peak/top). Germany's highest mountain at 2,962m. On the Austrian border. The name may come from avalanche channels ('Z\u00fcge') that mark its face. Die Zugspitze is feminine."},
{type:"teach",trg:"der Zwiebelturm",src:"onion dome tower",pos:"noun",gender:"m",note:"Zwiebel (onion) + Turm (tower). The iconic Bavarian\nchurch towers with bulbous domes.",example:"A: Warum haben bayerische Kirchen Zwiebelt\u00fcrme?\nB: Das wei\u00df niemand genau.\nA: Vielleicht wegen des Schnees?\nB: M\u00f6glicherweise. Die Form leitet Schnee ab.",exampleSrc:"A: Why do Bavarian churches have onion dome towers?\nB: Nobody knows exactly.\nA: Maybe because of the snow?\nB: Possibly. The shape deflects snow.",funFact:"Zwiebel (onion) + Turm (tower). The iconic church towers of Bavaria and Austria with their bulbous domes. Nobody knows exactly why the onion shape developed. Some say it sheds snow better."},
{type:"teach",trg:"die Zunft",src:"guild, medieval craft association",pos:"noun",gender:"f",note:"From Old High German 'zumft' (what is fitting).\nBakers, blacksmiths, weavers each had their Zunft.",example:"A: Was war eine Zunft?\nB: Eine mittelalterliche Handwerkervereinigung.\nA: Gibt es heute noch Z\u00fcnfte?\nB: Als Kulturvereine, ja.",exampleSrc:"A: What was a guild?\nB: A medieval craftsmen's association.\nA: Do guilds still exist today?\nB: As cultural associations, yes.",funFact:"From Old High German 'zumft' (what is fitting). Bakers, blacksmiths, weavers: each had their Zunft with strict rules. Some Z\u00fcnfte survive as cultural associations. Freiburg's Zunfth\u00e4user still stand."},
{type:"teach",trg:"das UNESCO-Welterbe",src:"UNESCO World Heritage Site",pos:"noun",gender:"n",note:"UNESCO + Welt (world) + Erbe (heritage). Germany\nhas 52 Welterbe sites. Neuter because Erbe is neuter.",example:"A: Ist der K\u00f6lner Dom UNESCO-Welterbe?\nB: Ja, seit 1996.\nA: Wie viele Welterbe-St\u00e4tten hat Deutschland?\nB: 52, von Burgen bis zum Wattenmeer.",exampleSrc:"A: Is Cologne Cathedral a UNESCO World Heritage Site?\nB: Yes, since 1996.\nA: How many World Heritage Sites does Germany have?\nB: 52, from castles to the Wadden Sea.",funFact:"UNESCO + Welt (world) + Erbe (heritage). Germany has 52 Welterbe sites: Cologne Cathedral, Bamberg's Altstadt, the Bauhaus buildings, the Wadden Sea. Neuter because Erbe (heritage) is neuter."},
{type:"teach",trg:"beherbergen",src:"to house, to accommodate",pos:"verb",gender:null,note:"Be- + herbergen (from Herberge, inn). Not separable.\nThe be- prefix makes it transitive.",example:"A: Was beherbergt dieses Museum?\nB: \u00dcber 10.000 Kunstwerke.\nA: Die Stadt beherbergt viele Touristen.\nB: Besonders im Sommer.",exampleSrc:"A: What does this museum house?\nB: Over 10,000 artworks.\nA: The city accommodates many tourists.\nB: Especially in summer.",funFact:"Be- + herbergen (from Herberge, inn/shelter). To house, to accommodate. 'Das Museum beherbergt 10.000 Werke.' Not separable. The be- prefix makes it transitive. You beherbergen guests, collections, or secrets."},
{type:"teach",trg:"errichten",src:"to erect, to build",pos:"verb",gender:null,note:"Er- + richten (to direct/set up). More formal than\n'bauen.' Used for significant structures.",example:"A: Wann wurde diese Burg errichtet?\nB: Im 12. Jahrhundert.\nA: Wer hat sie errichtet?\nB: Vermutlich ein lokaler F\u00fcrst.",exampleSrc:"A: When was this castle erected?\nB: In the 12th century.\nA: Who erected it?\nB: Presumably a local prince.",funFact:"Er- + richten (to direct/set up). To erect, to build. 'Die Burg wurde im 12. Jahrhundert errichtet.' More formal than 'bauen.' Used for significant structures. Not separable."},
{type:"teach",trg:"restaurieren",src:"to restore",pos:"verb",gender:null,note:"From Latin 'restaurare.' Same word in English\nand French. Used for historic buildings and art.",example:"A: Wird das Schloss restauriert?\nB: Ja, seit drei Jahren.\nA: Restaurieren kostet viel Geld.\nB: Aber es lohnt sich f\u00fcr das Kulturerbe.",exampleSrc:"A: Is the palace being restored?\nB: Yes, for three years.\nA: Restoring costs a lot of money.\nB: But it is worth it for the cultural heritage.",funFact:"From Latin 'restaurare' (to restore). 'Das Schloss wurde aufwendig restauriert.' Same word in English and French. Germans restaurieren historic buildings meticulously."},
{type:"teach",trg:"pr\u00e4sentieren",src:"to present, to showcase",pos:"verb",gender:null,note:"From Latin 'praesentare.' Same word across European\nlanguages. Formal but widely used.",example:"A: Die Stadt pr\u00e4sentiert ihr Kulturerbe.\nB: Wie pr\u00e4sentiert sie es?\nA: Mit Stadtf\u00fchrungen und Museen.\nB: Das ist eine gute Strategie.",exampleSrc:"A: The city showcases its cultural heritage.\nB: How does it showcase it?\nA: With city tours and museums.\nB: That is a good strategy.",funFact:"From Latin 'praesentare' (to present). 'Die Stadt pr\u00e4sentiert ihr Kulturerbe.' Same word across European languages. Formal but widely used."},
{type:"teach",trg:"\u00fcberall",src:"everywhere",pos:"adv",gender:null,note:"\u00dcber (over) + all (all). A lokal adverb.\nLiterally 'over all' places.",example:"A: Wo gibt es Fachwerkh\u00e4user?\nB: \u00dcberall in Deutschland.\nA: \u00dcberall?\nB: Na ja, besonders in der Mitte und im S\u00fcden.",exampleSrc:"A: Where are there half-timbered houses?\nB: Everywhere in Germany.\nA: Everywhere?\nB: Well, especially in the center and south.",funFact:"\u00dcber (over) + all (all). Everywhere. A lokal adverb. '\u00dcberall in Deutschland gibt es sch\u00f6ne Orte.' Literally 'over all' places. The broadest possible location."},
{type:"teach",trg:"irgendwo",src:"somewhere",pos:"adv",gender:null,note:"Irgend (some-) + wo (where). Part of the irgend-\nfamily. The sister of 'nirgendwo' (nowhere).",example:"A: Wo ist das Caf\u00e9?\nB: Irgendwo in der Altstadt.\nA: Irgendwo? Das hilft mir nicht.\nB: In der N\u00e4he des M\u00fcnsters, glaube ich.",exampleSrc:"A: Where is the caf\u00e9?\nB: Somewhere in the old town.\nA: Somewhere? That does not help me.\nB: Near the cathedral, I think.",funFact:"Irgend (some-) + wo (where). Somewhere. 'Irgendwo in S\u00fcddeutschland.' Part of the 'irgend-' family. Vague on purpose. The sister of 'nirgendwo' (nowhere)."},
{type:"mc",q:"Welcher Satz hat die korrekte TeKaMoLo-Reihenfolge? 'Lukas hat...'",opts:["gestern Abend aus Freude leidenschaftlich in Freiburg gespielt","in Freiburg gestern Abend leidenschaftlich aus Freude gespielt","leidenschaftlich gestern Abend in Freiburg aus Freude gespielt","aus Freude in Freiburg gestern Abend leidenschaftlich gespielt"],ans:"gestern Abend aus Freude leidenschaftlich in Freiburg gespielt",hint:"Te(mporal): gestern Abend. Ka(usal): aus Freude. Mo(dal): leidenschaftlich. Lo(kal): in Freiburg.",sSrc:"Which sentence has the correct TeKaMoLo order? 'Lukas has...'"},
{type:"fb",s:"In einem deutschen Kompositum bestimmt das {1} das grammatische Geschlecht.",a:["Grundwort"],opts:["Grundwort","Bestimmungswort","Fugenelement","Pr\u00e4fix"],hint:"This grammatical term names the element that always comes last in a compound and controls its gender.",sSrc:"In a German compound noun, the ___ determines the grammatical gender."},
{type:"drag_fill",s:"Es ist {1}, dass so viel Kulturerbe {2} wurde. Aber vieles wurde auch {3}.",blanks:{"1":"unglaublich","2":"zerst\u00f6rt","3":"restauriert"},pool:["unglaublich","zerst\u00f6rt","restauriert","missverstanden","unm\u00f6glich","errichtet"],hint:"It is un-believable that heritage was des-troyed. But much was also re-stored.",sSrc:"It is unbelievable that so much cultural heritage was destroyed. But much was also restored."},
{type:"match",pairs:[{trg:"Tiefebene",src:"lowland plain"},{trg:"Mittelgebirge",src:"low mountain range"},{trg:"Zugspitze",src:"Germany's highest peak"},{trg:"K\u00fcstenregion",src:"coastal region"},{trg:"Flusslandschaft",src:"river landscape"}]},
{type:"mc",q:"'Die mittelalterliche Burg wurde vermutlich im 13. Jahrhundert wegen ihrer strategischen Lage hoch \u00fcber dem Tal errichtet.' Welche B2-Konstrukte erscheinen?",opts:["Nur TeKaMoLo","Nur Wortbildung","Nur ein Negationspr\u00e4fix","TeKaMoLo + Wortbildung (mittelalterliche) + Modaladverb (vermutlich)"],ans:"TeKaMoLo + Wortbildung (mittelalterliche) + Modaladverb (vermutlich)",hint:"The sentence orders adverbs correctly, uses a compound adjective, and a probability adverb.",sSrc:"Which B2 constructs appear in: 'The medieval castle was presumably erected in the 13th century because of its strategic location high above the valley'?"}
]},
{id:"deu_r34l7",title:"Deutschlandquiz",icon:"\uD83C\uDDE9\uD83C\uDDEA",xp:15,board:true,steps:[
{type:"intro",title:"Deutschlandquiz",desc:"Test everything from Unit 34. Prove you can decompose compounds, negate with prefixes, and order adverbs.",goals:["Decompose compounds into their parts","Negate with un-, miss-, and zer-","Order adverbs according to TeKaMoLo"]},
{type:"teach",trg:"besiedeln",src:"to colonize, to settle (an area)",pos:"verb",gender:null,note:"Be- + siedeln (to settle). Transitive: you besiedeln\na place. Not separable. Historical vocabulary.",example:"A: Wer besiedelte das Rheinland?\nB: Die R\u00f6mer, vor 2.000 Jahren.\nA: Und sp\u00e4ter?\nB: Germanische St\u00e4mme besiedelten es danach.",exampleSrc:"A: Who settled the Rhineland?\nB: The Romans, 2,000 years ago.\nA: And later?\nB: Germanic tribes settled it afterward.",funFact:"Be- + siedeln (to settle). 'Die R\u00f6mer besiedelten das Rheinland.' The be- prefix makes it transitive: you besiedeln a place. Not separable. Historical vocabulary."},
{type:"teach",trg:"durchstreifen",src:"to roam through, to wander across",pos:"verb",gender:null,note:"Durch (through) + streifen (to roam). Not separable.\nMore poetic than 'durchqueren.' No fixed route.",example:"A: Wir haben den Schwarzwald durchstreift.\nB: Wie lange wart ihr unterwegs?\nA: Drei Tage, ohne festes Ziel.\nB: Das klingt wunderbar.",exampleSrc:"A: We roamed through the Black Forest.\nB: How long were you on the go?\nA: Three days, without a fixed destination.\nB: That sounds wonderful.",funFact:"Durch (through) + streifen (to roam). To roam through, to wander across. 'Den Schwarzwald durchstreifen.' Not separable (inseparable durch-). More poetic than 'durchqueren.' Implies no fixed route."},
{type:"teach",trg:"instandhalten",src:"to maintain, to keep in repair",pos:"verb",gender:null,note:"Instand (in good condition) + halten (to keep).\nSeparable. The verb for heritage preservation.",example:"A: Wer h\u00e4lt die Burg instand?\nB: Die Gemeinde.\nA: Das kostet viel Geld.\nB: Ja, aber es ist wichtig f\u00fcr das Kulturerbe.",exampleSrc:"A: Who maintains the castle?\nB: The municipality.\nA: That costs a lot of money.\nB: Yes, but it is important for the cultural heritage.",funFact:"Instand (in good condition) + halten (to keep). To maintain, to keep in repair. 'Das Bauwerk muss instandgehalten werden.' Separable. Every Denkmalschutz (monument protection) office instandh\u00e4lt."},
{type:"teach",trg:"umgestalten",src:"to redesign, to transform",pos:"verb",gender:null,note:"Um (re-/around) + gestalten (to design). Separable.\nThe verb for urban renewal and redesign.",example:"A: Die Altstadt wurde umgestaltet.\nB: Wie wurde sie umgestaltet?\nA: Neue Fu\u00dfg\u00e4ngerzonen und Gr\u00fcnfl\u00e4chen.\nB: Das klingt nach einer guten Umgestaltung.",exampleSrc:"A: The old town was redesigned.\nB: How was it redesigned?\nA: New pedestrian zones and green spaces.\nB: That sounds like a good transformation.",funFact:"Um (re-/around) + gestalten (to design/shape). To redesign, to transform. 'Die Altstadt wurde umgestaltet.' Separable. You umgestalten what already exists into something new."},
{type:"teach",trg:"umfahren",src:"to drive around (insep.) / to knock down (sep.)",pos:"verb",gender:null,note:"Two meanings depending on stress. Inseparable 'umFAHREN'\n= drive around. Separable 'UMfahren' = knock down.",example:"A: Ich habe die Baustelle umfahren.\nB: Gut, dann bist du drum herum gefahren.\nA: Letzte Woche habe ich fast einen Poller umgefahren.\nB: Das w\u00e4re nicht so gut gewesen!",exampleSrc:"A: I drove around the construction site.\nB: Good, then you went around it.\nA: Last week I almost knocked over a bollard.\nB: That would not have been so good!",funFact:"Two meanings depending on stress. 'UMfahren' (separable, to knock down by driving over) vs. 'umFAHREN' (inseparable, to drive around). A famous German grammar trap."},
{type:"teach",trg:"nirgendwo",src:"nowhere",pos:"adv",gender:null,note:"Nirgend (nowhere) + wo (where). The negative twin\nof 'irgendwo' and '\u00fcberall.' A complete set.",example:"A: Nirgendwo ist es sch\u00f6ner als hier.\nB: Das sagst du \u00fcberall.\nA: Aber hier meine ich es ernst.\nB: Nirgendwo sonst gibt es solche Berge.",exampleSrc:"A: Nowhere is it more beautiful than here.\nB: You say that everywhere.\nA: But here I mean it.\nB: Nowhere else are there such mountains.",funFact:"Nirgend (nowhere) + wo (where). Nowhere. 'Nirgendwo ist es sch\u00f6ner als hier.' The negative twin of 'irgendwo' (somewhere) and '\u00fcberall' (everywhere). Three location adverbs forming a complete set."},
{type:"teach",trg:"flussabw\u00e4rts",src:"downstream",pos:"adv",gender:null,note:"Fluss (river) + abw\u00e4rts (downward). A lokal adverb.\nOpposite: flussaufw\u00e4rts (upstream).",example:"A: Wohin fahren wir?\nB: Flussabw\u00e4rts, Richtung Heidelberg.\nA: Und flussaufw\u00e4rts?\nB: Da liegt Basel, in der Schweiz.",exampleSrc:"A: Where are we heading?\nB: Downstream, toward Heidelberg.\nA: And upstream?\nB: There lies Basel, in Switzerland.",funFact:"Fluss (river) + abw\u00e4rts (downward). Downstream. 'Flussabw\u00e4rts liegt Heidelberg.' The opposite: 'flussaufw\u00e4rts' (upstream). Directional compound specific to river geography."},
{type:"teach",trg:"unglaublich",src:"unbelievable, incredible",pos:"adj",gender:null,note:"Un- + glaublich (believable). The most common un-\nword in everyday German. Also an intensifier.",example:"A: Die Aussicht ist unglaublich!\nB: Unglaublich sch\u00f6n, ja.\nA: Unglaublich, dass wir hier sind.\nB: Manchmal ist die Realit\u00e4t unglaublich.",exampleSrc:"A: The view is incredible!\nB: Incredibly beautiful, yes.\nA: Unbelievable that we are here.\nB: Sometimes reality is unbelievable.",funFact:"Un- + glaublich (believable). Unbelievable, incredible. 'Unglaublich sch\u00f6n!' The most common un- word in everyday German. Used both literally and as an intensifier."},
{type:"teach",trg:"unm\u00f6glich",src:"impossible",pos:"adj",gender:null,note:"Un- + m\u00f6glich (possible). Also describes rude behavior:\n'Er ist unm\u00f6glich' (He is insufferable).",example:"A: Das ist unm\u00f6glich!\nB: Warum unm\u00f6glich?\nA: Die Aufgabe ist einfach zu schwer.\nB: Schwer, aber nicht unm\u00f6glich.",exampleSrc:"A: That is impossible!\nB: Why impossible?\nA: The task is simply too hard.\nB: Hard, but not impossible.",funFact:"Un- + m\u00f6glich (possible). Impossible. 'Das ist unm\u00f6glich.' Also used to describe rude behavior: 'Er ist unm\u00f6glich' (He is impossible/insufferable). Double duty."},
{type:"teach",trg:"unbedingt",src:"absolutely, by all means",pos:"adv",gender:null,note:"Un- + bedingt (conditional). Paradoxically, un- here\nintensifies rather than negates. One of the trickiest.",example:"A: Du musst unbedingt kommen!\nB: Wirklich? Unbedingt?\nA: Ja, es wird unbedingt toll.\nB: Dann komme ich unbedingt.",exampleSrc:"A: You absolutely must come!\nB: Really? Absolutely?\nA: Yes, it will definitely be great.\nB: Then I will definitely come.",funFact:"Un- + bedingt (conditional). Unconditional, absolutely, by all means. 'Du musst unbedingt kommen!' Paradoxically, un- here intensifies rather than negates. One of the trickiest un- words."},
{type:"teach",trg:"unverst\u00e4ndlich",src:"incomprehensible",pos:"adj",gender:null,note:"Un- + verst\u00e4ndlich (understandable). When Hochdeutsch\nspeakers meet strong dialect, this is the word.",example:"A: Sein Dialekt ist unverst\u00e4ndlich.\nB: F\u00fcr mich auch.\nA: Das ist v\u00f6llig unverst\u00e4ndlich.\nB: Man braucht Jahre, um das zu verstehen.",exampleSrc:"A: His dialect is incomprehensible.\nB: For me too.\nA: That is completely incomprehensible.\nB: You need years to understand that.",funFact:"Un- + verst\u00e4ndlich (understandable). Incomprehensible. 'Sein Dialekt ist unverst\u00e4ndlich.' When Hochdeutsch speakers meet strong dialect, this is the word they reach for."},
{type:"teach",trg:"unertr\u00e4glich",src:"unbearable, intolerable",pos:"adj",gender:null,note:"Un- + ertr\u00e4glich (bearable). Three layers of word\nformation: ertragen + -lich + un-.",example:"A: Die Hitze ist unertr\u00e4glich.\nB: Ja, fast 40 Grad.\nA: Unertr\u00e4glich hei\u00df.\nB: Lass uns ins Freibad gehen.",exampleSrc:"A: The heat is unbearable.\nB: Yes, almost 40 degrees.\nA: Unbearably hot.\nB: Let us go to the outdoor pool.",funFact:"Un- + ertr\u00e4glich (bearable). Unbearable, intolerable. 'Die Hitze ist unertr\u00e4glich.' Ertragen (to endure) + -lich + un-. Three layers of word formation in one adjective."},
{type:"teach",trg:"zerbrechen",src:"to shatter, to break into pieces",pos:"verb",gender:null,note:"Zer- + brechen (to break). Stronger than 'brechen.'\nZer- implies complete destruction.",example:"A: Das Glas ist zerbrochen.\nB: In tausend St\u00fccke.\nA: Zerbrechen ist endg\u00fcltig.\nB: Ja, das kann man nicht reparieren.",exampleSrc:"A: The glass shattered.\nB: Into a thousand pieces.\nA: Shattering is final.\nB: Yes, you cannot repair that.",funFact:"Zer- + brechen (to break). To shatter, to break into pieces. 'Das Glas ist zerbrochen.' Stronger than 'brechen' (break). Zer- implies complete destruction, not just damage."},
{type:"teach",trg:"zerrei\u00dfen",src:"to tear apart, to rip to pieces",pos:"verb",gender:null,note:"Zer- + rei\u00dfen (to tear). Violent destruction by tearing.\nThe zer- prefix escalates the action.",example:"A: Er hat den Brief zerrissen.\nB: Warum?\nA: Er war w\u00fctend.\nB: Zerrissenes Papier \u00fcberall.",exampleSrc:"A: He tore the letter apart.\nB: Why?\nA: He was angry.\nB: Torn paper everywhere.",funFact:"Zer- + rei\u00dfen (to tear). To tear apart, to rip to pieces. 'Er hat den Brief zerrissen.' Violent destruction by tearing. The zer- prefix escalates the action."},
{type:"teach",trg:"zerfallen",src:"to decay, to disintegrate",pos:"verb",gender:null,note:"Zer- + fallen (to fall). Slow, passive destruction.\nTime zerf\u00e4llt things. Inevitable decay.",example:"A: Die alte Burg zerf\u00e4llt.\nB: Niemand h\u00e4lt sie instand.\nA: Zerfallen ist ein langsamer Prozess.\nB: Aber genauso zerst\u00f6rerisch wie zerbrechen.",exampleSrc:"A: The old castle is decaying.\nB: Nobody maintains it.\nA: Decay is a slow process.\nB: But just as destructive as shattering.",funFact:"Zer- + fallen (to fall). To decay, to disintegrate, to fall apart. 'Die alte Burg zerf\u00e4llt.' A slow, passive destruction. Time zerf\u00e4llt things. Not sudden like zerbrechen, but inevitable."},
{type:"teach",trg:"zerlegen",src:"to disassemble, to take apart",pos:"verb",gender:null,note:"Zer- + legen (to lay). Can be constructive: a mechanic\nzerlegt an engine to fix it. Also for words.",example:"A: Kannst du das Wort zerlegen?\nB: Klar: Natur + Schutz + Gebiet.\nA: Zerlegen hilft beim Verstehen.\nB: Jedes lange Wort l\u00e4sst sich zerlegen.",exampleSrc:"A: Can you take the word apart?\nB: Sure: Natur + Schutz + Gebiet.\nA: Taking apart helps with understanding.\nB: Every long word can be taken apart.",funFact:"Zer- + legen (to lay). To disassemble, to take apart, to dissect. 'Das Wort in Teile zerlegen' (to dissect the word into parts). Can be constructive: a mechanic zerlegt an engine to fix it."},
{type:"mc",q:"'Unm\u00f6glich, misslungen, zerfallen.' Welche Beschreibung passt?",opts:["Unm\u00f6glich, gescheitert, verfallen. Steigende Schwere.","Alle bedeuten dasselbe.","Alle sind positiv.","Nur das letzte ist negativ."],ans:"Unm\u00f6glich, gescheitert, verfallen. Steigende Schwere.",hint:"Un- = cannot be. Miss- = went wrong. Zer- = completely fallen apart. Three levels of darkness.",sSrc:"'Impossible, failed, decayed.' Which description fits?"},
{type:"fb",s:"Das Grundwort bestimmt das {1} des zusammengesetzten Substantivs.",a:["Geschlecht"],opts:["Geschlecht","Wort","Satz","Verb"],hint:"The base word determines the property that makes it der, die, or das.",sSrc:"The base word determines the ___ of the compound noun."},
{type:"drag_fill",s:"Wir sind {1} {2} {3} durch den Schwarzwald {4}.",blanks:{"1":"heute Morgen","2":"wegen des sch\u00f6nen Wetters","3":"freudig","4":"gewandert"},pool:["heute Morgen","wegen des sch\u00f6nen Wetters","freudig","gewandert","gestern","nach Freiburg"],hint:"When? This morning. Why? Because of the weather. How? Joyfully. The verb goes at the end.",sSrc:"We hiked through the Black Forest this morning because of the nice weather joyfully."},
{type:"mc",q:"'Ich habe die Baustelle umfahren.' Was ist passiert?",opts:["Ich habe die Baustelle umgesto\u00dfen","Ich bin durch die Baustelle gefahren","Ich bin um die Baustelle herumgefahren (untrennbar)","Ich habe an der Baustelle gehalten"],ans:"Ich bin um die Baustelle herumgefahren (untrennbar)",hint:"When um- is inseparable (umFAHREN), it means 'to drive around.' Separable (UMfahren) means 'to knock over.'",sSrc:"'I drove around the construction site.' What happened?"},
{type:"match",pairs:[{trg:"unglaublich",src:"unbelievable"},{trg:"missverstehen",src:"to misunderstand"},{trg:"zerbrechen",src:"to shatter"},{trg:"unm\u00f6glich",src:"impossible"},{trg:"zerfallen",src:"to decay"}]},
{type:"fb",s:"Die Touristenf\u00fchrerin erkl\u00e4rt: 'Dieses Geb\u00e4ude ist eine echte Sehenswuerdigkeit.' Das mittlere Element bedeutet {1}.",a:["w\u00fcrdig"],opts:["w\u00fcrdig","wert","gut","sch\u00f6n"],hint:"The middle element of this compound means deserving or meriting something. Related to 'Wuerde' (dignity) but functioning as an adjective suffix.",sSrc:"The tourist guide explains: 'This building is a real attraction.' The middle element means ___."},
{type:"drag_fill",s:"Es ist {1}, dass man {2} in Deutschland {3} sch\u00f6ne Orte {4} kann.",blanks:{"1":"unglaublich","2":"\u00fcberall","3":"m\u00f6glicherweise","4":"entdecken"},pool:["unglaublich","\u00fcberall","m\u00f6glicherweise","entdecken","unm\u00f6glich","nirgendwo"],hint:"It is un-believable that one can possibly (modal) discover beautiful places everywhere (local).",sSrc:"It is unbelievable that one can possibly discover beautiful places everywhere in Germany."},
{type:"mc",q:"W\u00f6rter auf -ung, -heit, -keit und -schaft sind immer...",opts:["maskulin (der)","feminin (die)","neutrum (das)","es variiert"],ans:"feminin (die)",hint:"'Die Bildung, die Freiheit, die M\u00f6glichkeit, die Freundschaft.' The pattern never breaks.",sSrc:"Words ending in -ung, -heit, -keit, and -schaft are always..."}
]},
{id:"deu_r34l8",title:"Schwarzwaldmorgen",icon:"\uD83C\uDF32",xp:15,board:true,steps:[
{type:"intro",title:"Schwarzwaldmorgen",desc:"Reflect on Germany's diversity. Master all suffix families. Review everything from Unit 34. Appreciate the journey.",goals:["Learn the key suffix families","Review all constructs from Unit 34","Reflect on the journey through Germany"]},
{type:"story",speaker:"narrator",mood:"peaceful",trg:"Sonntagmorgen. Der Schwarzwald. Ein Aussichtspunkt \u00fcber dem Nebel. Die B\u00e4ume sind dunkel und uralt. Die T\u00e4ler unten verstecken sich im Wei\u00df. Die Sonne ber\u00fchrt gerade die Baumwipfel. Die Gruppe steht zusammen, ausnahmsweise still.",src:"Sunday morning. The Black Forest. A viewpoint above the mist. The trees are dark and ancient. The valleys below are hidden in white. The sun is just touching the treetops. The group stands together, quiet for once."},
{type:"story",speaker:"verumius",mood:"thoughtful",trg:"Das ist auch Deutschland. Nicht nur Berlin, nicht nur Grammatik. Bundesl\u00e4nder, Dialekte, Berge, Fl\u00fcsse, Burgen. Ein ganzes Land.",src:"This is also Germany. Not just Berlin, not just grammar. Federal states, dialects, mountains, rivers, castles. An entire country."},
{type:"story",speaker:"hildi",mood:"warm",trg:"Du hast viel gelernt auf dieser Reise, Verumius. Nicht nur W\u00f6rter.",src:"You have learned a lot on this trip, Verumius. Not just words."},
{type:"story",speaker:"mia",mood:"smiling",trg:"Und du hast das Kettenw\u00f6rterspiel gewonnen. Lampenfieber. Das vergesse ich nicht.",src:"And you won the chain word game. Stage fright. I will not forget that."},
{type:"story",speaker:"lukas",mood:"relaxed",trg:"N\u00e4chstes Mal fahren wir an die Nordsee. Dann lernst du Plattdeutsch.",src:"Next time we will drive to the North Sea. Then you will learn Low German."},
{type:"story",speaker:"verumius",mood:"happy",trg:"M\u00f6glicherweise verstehe ich dann gar nichts mehr. Aber irgendwie schaffe ich das.",src:"Possibly I will not understand anything anymore. But somehow I will manage."},
{type:"teach",trg:"missachten",src:"to disregard, to ignore disrespectfully",pos:"verb",gender:null,note:"Miss- + achten (to regard/respect). Stronger than\n'nicht beachten.' Implies willful wrongdoing.",example:"A: Er missachtet die Regeln.\nB: Das ist gef\u00e4hrlich.\nA: Regeln missachten hat Konsequenzen.\nB: Ja, besonders im Stra\u00dfenverkehr.",exampleSrc:"A: He disregards the rules.\nB: That is dangerous.\nA: Disregarding rules has consequences.\nB: Yes, especially in traffic.",funFact:"Miss- + achten (to regard/respect). To disregard, to ignore disrespectfully. 'Die Regeln missachten' (to disregard the rules). Stronger than 'nicht beachten.' Miss- implies willful wrongdoing."},
{type:"teach",trg:"misslingen",src:"to fail, to not succeed",pos:"verb",gender:null,note:"Miss- + lingen (to succeed). The opposite of 'gelingen.'\nNot separable. Past participle: misslungen.",example:"A: Der Versuch ist misslungen.\nB: Was ist schiefgegangen?\nA: Alles. Es ist v\u00f6llig misslungen.\nB: Dann versuchen wir es noch einmal.",exampleSrc:"A: The attempt failed.\nB: What went wrong?\nA: Everything. It failed completely.\nB: Then we will try again.",funFact:"Miss- + lingen (to succeed). To fail, to not succeed. 'Der Versuch ist misslungen.' The opposite of 'gelingen' (to succeed). Not separable. The past participle is unusual: misslungen (not gemisslungen)."},
{type:"teach",trg:"das Missverst\u00e4ndnis",src:"misunderstanding",pos:"noun",gender:"n",note:"Miss- + Verst\u00e4ndnis (understanding). Neuter because\nVerst\u00e4ndnis is neuter. The noun of missverstehen.",example:"A: Es gab ein Missverst\u00e4ndnis.\nB: Was f\u00fcr ein Missverst\u00e4ndnis?\nA: Ich dachte, wir treffen uns um drei.\nB: Nein, um vier. Typisches Missverst\u00e4ndnis.",exampleSrc:"A: There was a misunderstanding.\nB: What kind of misunderstanding?\nA: I thought we were meeting at three.\nB: No, at four. Typical misunderstanding.",funFact:"Miss- + Verst\u00e4ndnis (understanding). A misunderstanding. 'Es gab ein Missverst\u00e4ndnis.' Das Missverst\u00e4ndnis is neuter because Verst\u00e4ndnis is neuter. The noun form of missverstehen."},
{type:"teach",trg:"missbrauchen",src:"to misuse, to abuse",pos:"verb",gender:null,note:"Miss- + brauchen (to use/need). Not separable.\nThe miss- prefix corrupts 'use' into 'misuse.'",example:"A: Macht darf man nicht missbrauchen.\nB: Das stimmt.\nA: Vertrauen missbrauchen ist schlimm.\nB: Ja, das zerst\u00f6rt Freundschaften.",exampleSrc:"A: Power must not be abused.\nB: That is true.\nA: Abusing trust is terrible.\nB: Yes, that destroys friendships.",funFact:"Miss- + brauchen (to use/need). To misuse, to abuse. 'Macht missbrauchen' (to abuse power). Not separable. The miss- prefix corrupts the neutral 'use' into harmful 'misuse.'"},
{type:"teach",trg:"die Freiheit",src:"freedom",pos:"noun",gender:"f",note:"Frei (free) + -heit. The -heit suffix creates abstract\nnouns from adjectives. Always feminine.",example:"A: Freiheit ist unbezahlbar.\nB: Ja, die Freiheit zu reisen.\nA: Die Freiheit zu lernen.\nB: Die Freiheit, Fehler zu machen.",exampleSrc:"A: Freedom is priceless.\nB: Yes, the freedom to travel.\nA: The freedom to learn.\nB: The freedom to make mistakes.",funFact:"Frei (free) + -heit. Freedom. 'Die Freiheit ist unbezahlbar.' The -heit suffix creates abstract nouns from adjectives. Always feminine. Germany's most treasured post-1989 word."},
{type:"teach",trg:"die Sch\u00f6nheit",src:"beauty",pos:"noun",gender:"f",note:"Sch\u00f6n (beautiful) + -heit. Same suffix as Freiheit.\nThe abstract quality of being beautiful.",example:"A: Die Sch\u00f6nheit der Landschaft ist atemberaubend.\nB: Ja, diese Sch\u00f6nheit gibt es nirgendwo sonst.\nA: Sch\u00f6nheit liegt im Auge des Betrachters.\nB: Aber hier sind sich alle einig.",exampleSrc:"A: The beauty of the landscape is breathtaking.\nB: Yes, this beauty exists nowhere else.\nA: Beauty is in the eye of the beholder.\nB: But here everyone agrees.",funFact:"Sch\u00f6n (beautiful) + -heit. Beauty. 'Die Sch\u00f6nheit der Landschaft.' Same suffix as Freiheit. The abstract quality of being beautiful. Always feminine."},
{type:"teach",trg:"die M\u00f6glichkeit",src:"possibility",pos:"noun",gender:"f",note:"M\u00f6glich (possible) + -keit. The -keit suffix appears\nafter -lich and -ig adjectives. Always feminine.",example:"A: Es gibt viele M\u00f6glichkeiten.\nB: Welche M\u00f6glichkeit w\u00e4hlst du?\nA: Die beste M\u00f6glichkeit.\nB: Manchmal gibt es keine gute M\u00f6glichkeit.",exampleSrc:"A: There are many possibilities.\nB: Which possibility do you choose?\nA: The best possibility.\nB: Sometimes there is no good possibility.",funFact:"M\u00f6glich (possible) + -keit. Possibility. 'Es gibt viele M\u00f6glichkeiten.' The -keit suffix appears after -lich and -ig adjectives. The world of what COULD happen. Always feminine."},
{type:"teach",trg:"die F\u00e4higkeit",src:"ability, skill",pos:"noun",gender:"f",note:"F\u00e4hig (capable) + -keit. Same pattern as M\u00f6glichkeit.\nThe -ig adjective takes -keit, not -heit.",example:"A: Sprachliche F\u00e4higkeiten sind wichtig.\nB: Welche F\u00e4higkeiten hast du?\nA: Ich spreche drei Sprachen.\nB: Das ist eine tolle F\u00e4higkeit.",exampleSrc:"A: Language skills are important.\nB: What skills do you have?\nA: I speak three languages.\nB: That is a great ability.",funFact:"F\u00e4hig (capable) + -keit. Ability, skill. 'Sprachliche F\u00e4higkeiten' (language skills). Same pattern as M\u00f6glichkeit. The -ig adjective takes -keit, not -heit. Always feminine."},
{type:"teach",trg:"die Landschaft",src:"landscape",pos:"noun",gender:"f",note:"Land + -schaft. The -schaft suffix creates collective\nor abstract nouns. Always feminine.",example:"A: Die deutsche Landschaft ist vielf\u00e4ltig.\nB: Von K\u00fcste bis Alpen.\nA: Jede Landschaft hat ihren Reiz.\nB: Besonders der Schwarzwald.",exampleSrc:"A: The German landscape is diverse.\nB: From coast to Alps.\nA: Every landscape has its charm.\nB: Especially the Black Forest.",funFact:"Land + -schaft. Landscape. 'Die deutsche Landschaft ist vielf\u00e4ltig.' The -schaft suffix creates collective or abstract nouns. Same suffix in Freundschaft, Wirtschaft, Gesellschaft. Always feminine."},
{type:"teach",trg:"die Freundschaft",src:"friendship",pos:"noun",gender:"f",note:"Freund (friend) + -schaft. The -schaft suffix implies\na collective state. This road trip strengthened theirs.",example:"A: Unsere Freundschaft ist stark.\nB: Ja, durch diese Reise noch st\u00e4rker.\nA: Freundschaft braucht gemeinsame Erlebnisse.\nB: Wie einen Roadtrip durch Deutschland.",exampleSrc:"A: Our friendship is strong.\nB: Yes, even stronger through this trip.\nA: Friendship needs shared experiences.\nB: Like a road trip through Germany.",funFact:"Freund (friend) + -schaft. Friendship. 'Unsere Freundschaft ist stark.' The -schaft suffix implies a collective state or condition. This road trip strengthened their Freundschaft."},
{type:"teach",trg:"der Reichtum",src:"wealth, richness",pos:"noun",gender:"m",note:"Reich (rich) + -tum. The -tum suffix usually creates\nmasculine nouns. Exception: das Wachstum.",example:"A: Der Reichtum der deutschen Kultur.\nB: Nicht nur materieller Reichtum.\nA: Kultureller Reichtum ist wichtiger.\nB: Traditionen, Sprachen, Landschaften.",exampleSrc:"A: The richness of German culture.\nB: Not just material wealth.\nA: Cultural richness is more important.\nB: Traditions, languages, landscapes.",funFact:"Reich (rich) + -tum. Wealth, richness. 'Der Reichtum der deutschen Kultur.' The -tum suffix usually creates masculine nouns (Reichtum, Irrtum). Exception: das Eigentum, das Wachstum."},
{type:"teach",trg:"das Wachstum",src:"growth",pos:"noun",gender:"n",note:"Wachsen (to grow) + -tum. Neuter, an exception to\nthe mostly-masculine -tum pattern.",example:"A: Wirtschaftswachstum ist wichtig.\nB: Aber nicht auf Kosten der Umwelt.\nA: Nachhaltiges Wachstum ist das Ziel.\nB: Wachstum mit Verantwortung.",exampleSrc:"A: Economic growth is important.\nB: But not at the expense of the environment.\nA: Sustainable growth is the goal.\nB: Growth with responsibility.",funFact:"Wachsen (to grow) + -tum. Growth. 'Wirtschaftswachstum' (economic growth). Das Wachstum is neuter, an exception to the mostly-masculine -tum pattern."},
{type:"teach",trg:"das Ergebnis",src:"result, outcome",pos:"noun",gender:"n",note:"Er- + geben (to give) + -nis. The -nis suffix usually\ncreates neuter nouns. What comes out of giving effort.",example:"A: Was ist das Ergebnis der Reise?\nB: Neue W\u00f6rter, neue Freunde.\nA: Ein gutes Ergebnis.\nB: Das beste Ergebnis \u00fcberhaupt.",exampleSrc:"A: What is the result of the trip?\nB: New words, new friends.\nA: A good result.\nB: The best result of all.",funFact:"Er- + geben (to give) + -nis. A result, an outcome. 'Das Ergebnis der Reise.' The -nis suffix creates neuter nouns (usually). What comes out of (er-) giving effort."},
{type:"teach",trg:"die Kenntnis",src:"knowledge, awareness",pos:"noun",gender:"f",note:"Kennen (to know) + -nis. Feminine, unlike most -nis\nnouns. One of the exceptions.",example:"A: Hast du Kenntnisse in Deutsch?\nB: Ja, gute Kenntnisse.\nA: Sprachkenntnisse sind wertvoll.\nB: Sie \u00f6ffnen T\u00fcren.",exampleSrc:"A: Do you have knowledge of German?\nB: Yes, good knowledge.\nA: Language skills are valuable.\nB: They open doors.",funFact:"Kennen (to know) + -nis. Knowledge, awareness. 'Sprachkenntnisse' (language knowledge) on a CV. Die Kenntnis is feminine, unlike most -nis nouns. One of the exceptions."},
{type:"teach",trg:"machbar",src:"feasible, doable",pos:"adj",gender:null,note:"Machen (to make/do) + -bar. The -bar suffix means\n'able to be X-ed.' Same as English '-able.'",example:"A: Ist das machbar?\nB: Ja, absolut machbar.\nA: In zwei Tagen?\nB: Schwierig, aber machbar.",exampleSrc:"A: Is that feasible?\nB: Yes, absolutely feasible.\nA: In two days?\nB: Difficult, but doable.",funFact:"Machen (to make/do) + -bar. Feasible, doable. 'Das ist machbar!' The -bar suffix creates adjectives meaning 'able to be X-ed.' Same as English '-able': machbar = makeable = doable."},
{type:"teach",trg:"l\u00f6sbar",src:"solvable",pos:"adj",gender:null,note:"L\u00f6sen (to solve) + -bar. Every puzzle, every grammar\nquestion: l\u00f6sbar. The optimistic -bar suffix.",example:"A: Ist das Problem l\u00f6sbar?\nB: Jedes Problem ist l\u00f6sbar.\nA: Auch Grammatikprobleme?\nB: Besonders die. Mit \u00dcbung.",exampleSrc:"A: Is the problem solvable?\nB: Every problem is solvable.\nA: Even grammar problems?\nB: Especially those. With practice.",funFact:"L\u00f6sen (to solve) + -bar. Solvable. 'Das Problem ist l\u00f6sbar.' Every puzzle, every Stau, every grammar question: l\u00f6sbar. The optimistic -bar suffix."},
{type:"mc",q:"Die meisten -tum-Substantive sind maskulin (der Reichtum). Welches ist eine Ausnahme?",opts:["der Irrtum","der Reichtum","der Brauchtum","das Wachstum"],ans:"das Wachstum",hint:"Most -tum nouns follow the masculine pattern, but one exception in the list comes from a verb of increase rather than a noun of state. Which option represents process or increase?",sSrc:"Most -tum nouns are masculine (der Reichtum). Which is an exception?"},
{type:"fb",s:"Der Plan ist leider {1}.",a:["misslungen"],opts:["misslungen","missglungen","gelungen","zerlungen"],hint:"The plan did not succeed. The miss- prefix turns success (gelingen) into failure.",sSrc:"The plan unfortunately failed."},
{type:"drag_fill",s:"Die {1} der Landschaft und die {2} der Menschen machen diese Reise {3}.",blanks:{"1":"Sch\u00f6nheit","2":"Freundschaft","3":"unbezahlbar"},pool:["Sch\u00f6nheit","Freundschaft","unbezahlbar","Freiheit","Reichtum","unm\u00f6glich"],hint:"The beauty of the landscape and the friendship of the people make the trip priceless (un- + bezahlbar).",sSrc:"The beauty of the landscape and the friendship of the people make this trip priceless."},
{type:"match",pairs:[{trg:"-heit/-keit",src:"feminines abstraktes Substantiv"},{trg:"-schaft",src:"feminines Kollektivsubstantiv"},{trg:"-tum",src:"meist maskulines Substantiv"},{trg:"-nis",src:"meist neutrales Substantiv"},{trg:"-bar",src:"Adjektiv (f\u00e4hig, etwas zu sein)"}]},
{type:"mc",q:"Verumius sagt: 'M\u00f6glicherweise verstehe ich dann gar nichts mehr.' Was repr\u00e4sentiert 'm\u00f6glicherweise' in TeKaMoLo?",opts:["Temporal (wann)","Modal (wie/auf welche Weise)","Kausal (warum)","Lokal (wo)"],ans:"Modal (wie/auf welche Weise)",hint:"Modal adverbs describe HOW something happens: m\u00f6glicherweise, gern, vermutlich. They stand third in TeKaMoLo.",sSrc:"Verumius says: 'Possibly I will not understand anything anymore.' What does 'm\u00f6glicherweise' represent in TeKaMoLo?"}
]}
]};

export default UNIT_34;
